VALUES ('VLR-SD-001', 'Set Nâu Cocoa Thanh Lịch Dự Tiệc', 'set-nau-cocoa-thanh-lich-du-tiec', 'Set đồ kết hợp áo kiểu bất đối xứng tông Cocoa cùng quần suông linen sáng màu, tạo nên tổng thể thanh lịch nhưng vẫn mềm mại và nữ tính. Thiết kế nhấn eo nhẹ giúp vóc dáng trông cân đối hơn, trong khi phom quần dài mang lại cảm giác chỉn chu, sang trọng. Phù hợp cho tiệc nhẹ, hẹn hò tối hoặc những buổi gặp gỡ cần vẻ ngoài tinh tế.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 3310000, 2990000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-nau-cocoa-thanh-lich-du-tiec_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-nau-cocoa-thanh-lich-du-tiec_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, true, 'Soft Ceremony', 'on_sale'::product_status)
