VALUES ('VLR-SD-002', 'Set Ivory Draped Thanh Nhã', 'set-ivory-draped-thanh-nha', 'Set đồ nổi bật với áo cape mềm mại tông Ivory kết hợp quần giả váy xếp phủ tạo hiệu ứng chuyển động uyển chuyển và sang trọng. Tổng thể mang tinh thần nữ tính, thanh lịch, phù hợp với những dịp cần sự chỉn chu vừa đủ nhưng không quá cứng nhắc. Đây là lựa chọn lý tưởng cho tiệc tối, chụp ảnh hoặc những buổi hẹn mang tính đặc biệt.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 3340000, 3050000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ivory-draped-thanh-nha_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ivory-draped-thanh-nha_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, true, 'Soft Ceremony', 'on_sale'::product_status)
