VALUES ('VLR-SD-003', 'Set Midnight Blue Chạm Eo Hiện Đại', 'set-midnight-blue-cham-eo-hien-dai', 'Áo kiểu wrap màu xanh đêm được phối cùng quần suông trắng ngà tạo nên tổng thể tương phản thanh lịch, hiện đại và sắc sảo. Phần eo được xử lý ôm nhẹ giúp tôn dáng, trong khi quần ống rộng giữ cho set đồ vẫn mềm mại và dễ ứng dụng. Phù hợp với các buổi tiệc, hẹn tối hoặc những dịp cần vẻ ngoài nổi bật nhưng tinh tế.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2650000, 2390000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-midnight-blue-cham-eo-hien-dai_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-midnight-blue-cham-eo-hien-dai_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Romantic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], true, false, 'Soft Ceremony', 'on_sale'::product_status)
