VALUES ('VLR-SD-004', 'Set Sage Pleated Dịu Nhẹ Cuối Tuần', 'set-sage-pleated-diu-nhe-cuoi-tuan', 'Set đồ mang bảng màu Sage – Ivory dịu mắt với áo dệt gân ôm nhẹ và quần suông dài tối giản, tạo cảm giác mềm mại, trẻ trung và tinh tế. Thiết kế phù hợp với tinh thần nữ tính hiện đại, dễ mặc trong các buổi cà phê, hẹn hò ban ngày hoặc chuyến đi ngắn cuối tuần. Tổng thể gọn gàng nhưng vẫn giữ được nét mềm mại rất đặc trưng của Velura.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 3590000, 3250000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-sage-pleated-diu-nhe-cuoi-tuan_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-sage-pleated-diu-nhe-cuoi-tuan_02.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Romantic', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Apple']::body_shape[], true, false, 'Soft Ceremony', 'on_sale'::product_status)
