VALUES ('VLR-SD-005', 'Set Gilet Cocoa Ánh Vàng Sang Tối', 'set-gilet-cocoa-anh-vang-sang-toi', 'Gilet tông Cocoa phối cùng quần suông trắng kem tạo nên một set đồ tối giản nhưng có điểm nhấn nhờ chất liệu và phụ kiện ánh vàng. Tổng thể mang vẻ sang trọng, trưởng thành và rất phù hợp cho tiệc tối, hẹn hò hoặc các dịp gặp gỡ cần sự nổi bật vừa phải. Set đồ cân bằng giữa nét cổ điển và tinh thần thanh lịch hiện đại.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 4670000, 4250000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-gilet-cocoa-anh-vang-sang-toi_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-gilet-cocoa-anh-vang-sang-toi_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, true, 'Soft Ceremony', 'on_sale'::product_status)
