VALUES ('VLR-SD-012', 'Set Áo Croptop 2in1 Váy Xếp Ly Preppy Cream Mocha', 'set-ao-croptop-2in1-vay-xep-ly-preppy-cream-mocha', 'Set đồ mùa đông ngọt ngào theo phong cách Korean soft girl, kết hợp áo croptop 2in1 dệt kim sọc nâu – tube top kem, cùng chân váy tennis xếp ly mini beige kèm thắt lưng nâu chocolate. Điểm nhấn là bịt tai lông ivory ấm áp và túi baguette vai kem nhạt. Boots tuyết lót lông off-white hoàn thiện tổng thể ấm cúng, dễ thương, cực kỳ phù hợp cho những ngày đông lạnh giá hay các buổi dạo phố mùa lễ hội.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2050000, 1750000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-len-cropped-soc-vay-xep-ly-preppy-campus-cream_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-len-cropped-soc-vay-xep-ly-preppy-campus-cream_02.png']::VARCHAR(255)[], ARRAY['Preppy', 'Classic', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], true, true, 'Midnight Mirage', 'on_sale'::product_status)
