VALUES ('VLR-SD-013', 'Set Áo Crop Cyber Váy Lace-Up Midi Dark Mirage', 'set-ao-crop-cyber-vay-lace-up-midi-dark-mirage', 'Set đồ thuộc bộ sưu tập Midnight Mirage, kết hợp giữa phong cách cyber streetwear và gothic Y2K. Gồm áo crop top cổ yếm họa tiết loang kèm bolero tay dài ôm, váy midi xẻ tà lace-up, túi tua rua đen và giày Mary Jane platform đế lông. Tổng thể bí ẩn, cá tính, là lựa chọn hoàn hảo cho những buổi tiệc tối, dạo phố đêm hoặc các sự kiện thời trang đường phố.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2170000, 1844500, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-crop-cyber-vay-lace-up-midi-dark-mirage_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-crop-cyber-vay-lace-up-midi-dark-mirage_02.png']::VARCHAR(255)[], ARRAY['Street', 'Minimalist', 'Elegant']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, true, 'Midnight Mirage', 'on_sale'::product_status)
