VALUES ('VLR-SD-014', 'Set Áo Sát Nách Logo Váy Xám Túi Hộp Grunge Mirage', 'set-ao-sat-nach-logo-vay-xam-tui-hop-grunge-mirage', 'Set đồ thuộc bộ sưu tập Midnight Mirage, pha trộn giữa phong cách streetwear Y2K và punk grunge. Gồm áo sát nách cổ cao đen logo trắng, váy mini xám bất đối xứng với túi hộp utility, túi đeo vai mini đen và boots biker đế platform đa khóa. Tổng thể mạnh mẽ, cá tính, lý tưởng cho các buổi dạo phố, tiệc tối hoặc sự kiện thời trang.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2010000, 1708500, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-sat-nach-graphic-vay-cargo-mini-grunge-street_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-sat-nach-graphic-vay-cargo-mini-grunge-street_02.png']::VARCHAR(255)[], ARRAY['Street', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, true, 'Midnight Mirage', 'on_sale'::product_status)
