VALUES ('VLR-SD-015', 'Set Áo Polo Cropped Sọc Quần Jeans Ống Rộng Preppy Grunge', 'set-ao-polo-cropped-soc-quan-jeans-ong-rong-preppy-grunge', 'Set đồ thuộc bộ sưu tập Midnight Mirage, pha trộn giữa phong cách preppy học sinh và grunge đường phố. Điểm nhấn là áo len cropped cổ polo sọc ngang với gấu rách tua, kết hợp cùng quần jeans ống cực rộng light wash xếp ly tạo hiệu ứng chân dài. Túi messenger đeo chéo và sneaker platform đế bánh mì hoàn thiện vẻ ngoài năng động, trong khi kính mát trắng đặt trên đầu tăng thêm vibe Y2K. Là outfit hoàn hảo cho những buổi dạo phố, cà phê hay gặp bạn bè.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2340000, 1989000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-polo-cropped-soc-quan-jeans-ong-rong-preppy-grunge_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-ao-polo-cropped-soc-quan-jeans-ong-rong-preppy-grunge_02.png']::VARCHAR(255)[], ARRAY['Street', 'Classic', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, false, 'Midnight Mirage', 'on_sale'::product_status)
