VALUES ('VLR-SD-016', 'Set Dạo Biển Linen Đen Kem', 'set-dao-bien-linen-den-kem', 'Set đồ kết hợp áo kiểu đen viền ren, quần linen ống rộng màu kem, túi tote, sandal quai ngang và kính râm tạo tổng thể nghỉ dưỡng thanh lịch. Chất liệu linen nhẹ, phối cùng phụ kiện đen và kem giúp outfit vừa thoải mái vừa có cảm giác sang nhẹ. Set phù hợp cho du lịch biển, dạo phố mùa hè, cà phê cuối tuần hoặc resort casual.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 1460000, 1299000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-dao-bien-linen-den-kem_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-dao-bien-linen-den-kem_2.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Boho', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, false, 'Weekend Escape', 'on_sale'::product_status)
