VALUES ('VLR-SD-017', 'Set Resort Lụa Olive Và Chân Váy Ivory', 'set-resort-lua-olive-va-chan-vay-ivory', 'Set đồ kết hợp áo lụa cổ yếm màu olive, chân váy mini ivory, túi cầm tay trắng kem, sandal cao gót, kính râm và vòng tay tạo tổng thể resort chic nữ tính. Chất liệu lụa mềm phối cùng gam olive và ivory mang cảm giác mùa hè sang nhẹ, nổi bật nhưng vẫn tinh tế. Set phù hợp cho du lịch biển, resort, dạo phố hoặc những buổi hẹn mùa hè.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 1710000, 1499000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-resort-lua-olive-va-chan-vay-ivory_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-resort-lua-olive-va-chan-vay-ivory_2.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, false, 'Weekend Escape', 'on_sale'::product_status)
