VALUES ('VLR-SD-018', 'Set White Resort Hẹn Hò Mùa Hè', 'set-white-resort-hen-ho-mua-he', 'Set đồ phối áo yếm trắng, quần ống rộng trắng, túi hồng pastel, giày búp bê ánh vàng và phụ kiện gold tạo tổng thể nữ tính, sáng và sang nhẹ. Chất liệu vải mềm, phom dáng thoải mái kết hợp cùng gam trắng chủ đạo giúp outfit phù hợp với mùa hè và không khí nghỉ dưỡng. Set phù hợp cho du lịch, dạo phố, cà phê cuối tuần hoặc hẹn hò ban ngày.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 2040000, 1799000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-white-resort-hen-ho-mua-he_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-white-resort-hen-ho-mua-he_2.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, false, 'Weekend Escape', 'on_sale'::product_status)
