VALUES ('VLR-SD-019', 'Set Boho Linen Hồng Kem Dạo Biển', 'set-boho-linen-hong-kem-dao-bien', 'Set đồ kết hợp áo blouse hồng pastel thêu ren, quần linen ống rộng màu kem, túi hobo nâu, sandal nâu và kính râm gọng vàng tạo tổng thể boho nữ tính, nhẹ nhàng. Chất liệu linen và vải mềm thoáng giúp outfit phù hợp với không khí mùa hè, vừa thoải mái vừa có điểm nhấn. Set phù hợp cho du lịch, dạo phố, cà phê cuối tuần hoặc các buổi đi chơi ban ngày.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 1540000, 1359000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-boho-linen-hong-kem-dao-bien_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-boho-linen-hong-kem-dao-bien_2.png']::VARCHAR(255)[], ARRAY['Boho', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], true, false, 'Weekend Escape', 'on_sale'::product_status)
