VALUES ('VLR-SD-020', 'Set Satin Champagne Và Chân Váy Đen', 'set-satin-champagne-va-chan-vay-den', 'Set đồ kết hợp áo satin hai dây màu champagne, chân váy mini đen, sandal cao gót đen và phụ kiện ánh vàng tạo tổng thể nổi bật, quyến rũ nhưng vẫn tinh tế. Chất liệu satin bóng nhẹ phối cùng gam đen giúp outfit có cảm giác sang chảnh, phù hợp với những buổi đi chơi mùa hè. Set phù hợp cho hẹn hò, tiệc nhẹ, dạo phố buổi tối hoặc kỳ nghỉ resort.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 1780000, 1559000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-satin-champagne-va-chan-vay-den_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_set-satin-champagne-va-chan-vay-den_2.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], true, false, 'Weekend Escape', 'on_sale'::product_status)
