VALUES ('VLR-SD-024', 'Set Đầm Dạ Hội Cổ Yếm Phối Ren Thượng Lưu The Afterglow Rose', 'set-dam-da-hoi-co-yem-phoi-ren-thuong-luu-the-afterglow-rose', 'Bản tình ca lãng mạn từ BST The Afterglow, kết hợp chiếc đầm cổ yếm phối ren tinh xảo cùng tùng váy ruffles dập ly uốn lượn sắc hồng khói hoàng gia. Đi kèm bộ phụ kiện vương miện vương giả, trang sức đính đá quý sắc hồng đồng điệu và túi clutch lụa quý phái, mang đến cho quý cô vẻ đẹp diễm lệ, ngọt ngào và kiêu kỳ tựa một nàng thơ.', (SELECT category_id FROM category WHERE slug = 'set-do' LIMIT 1), 26200000, 24099000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_co-yem-phoi-ren-the-afterglow_rose_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/set-do/set-do_co-yem-phoi-ren-the-afterglow_rose_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], true, true, 'The Afterglow', 'on_sale'::product_status)
