VALUES ('VLR-AO-004', 'Áo Blouse Tay Phồng Voan Kem Nhẹ', 'ao-blouse-tay-phong-voan-kem-nhe', 'Thiết kế peplum nhấn eo nhẹ kết hợp cổ vuông giúp tôn phần cổ và vai một cách mềm mại. Chất liệu cotton pha đứng phom vừa đủ, tạo hiệu ứng gọn gàng ở vòng eo và cân đối phần hông. Sắc Sage đem lại cảm giác tinh tế, hiện đại nhưng vẫn giữ được chất thơ rất riêng của Velura.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 640000, 840000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-blouse-tay-phong-voan-kem-nhe_beige_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Pear']::body_shape[], false, true, NULL, 'on_sale'::product_status)
