VALUES ('VLR-AO-005', 'Áo Sơ Mi Cổ Đức Oat Milk Tối Giản', 'ao-so-mi-co-duc-oat-milk-toi-gian', 'Mẫu sơ mi cổ Đức được thiết kế theo tinh thần tối giản với đường cắt gọn, dễ ứng dụng trong nhiều hoàn cảnh. Chất liệu cotton premium mềm tay, thoáng và giữ phom tốt khi sơ vin. Gam Oat Milk trung tính giúp sản phẩm dễ kết hợp với bảng màu công sở lẫn phong cách thường ngày.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 560000, 760000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-so-mi-co-duc-oat-milk-toi-gian_beige_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Apple']::body_shape[], false, true, NULL, 'on_sale'::product_status)
