VALUES ('VLR-AO-006', 'Áo Satin Cổ V Tà Rủ Rose Dust', 'ao-satin-co-v-ta-ru-rose-dust', 'Áo satin cổ V với phần tà rủ mềm tạo chuyển động nhẹ khi mặc, giúp tổng thể thanh thoát và mềm mại hơn. Tông Rose Dust nữ tính nhưng không quá ngọt, phù hợp với những cô gái theo đuổi vẻ đẹp trưởng thành và tinh tế. Sản phẩm lý tưởng cho buổi hẹn tối, tiệc nhẹ hoặc môi trường làm việc sáng tạo.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 650000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-satin-co-v-ta-ru-rose-dust_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, true, NULL, 'on_sale'::product_status)
