VALUES ('VLR-AO-008', 'Áo Blouse Cổ Nơ Blush Pink Dịu Dàng', 'ao-blouse-co-no-blush-pink-diu-dang', 'Chi tiết cổ nơ mềm tạo điểm nhấn nữ tính vừa phải, giúp chiếc blouse trở nên duyên dáng mà vẫn thanh lịch. Bề mặt vải nhẹ, rủ đẹp và tạo cảm giác mềm mại trong chuyển động. Sắc Blush Pink mang đến tinh thần ngọt ngào, phù hợp với những bản phối theo hướng cổ điển lãng mạn.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 610000, 810000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-blouse-co-no-blush-pink-diu-dang_pink_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, true, NULL, 'on_sale'::product_status)
