VALUES ('VLR-AO-009', 'Áo Len Gân Cổ Tim Mocha Ôm Nhẹ', 'ao-len-gan-co-tim-mocha-om-nhe', 'Mẫu áo len gân cổ tim ôm nhẹ cơ thể, mang đến cảm giác gọn gàng và thanh lịch trong ngày se lạnh. Chất len dệt mềm, co giãn tốt và không quá dày, phù hợp để mặc riêng hoặc layer cùng blazer. Tông Mocha ấm áp giúp tổng thể trông chững chạc, tinh tế và dễ phối.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 480000, 680000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-len-gan-co-tim-mocha-om-nhe_mocha_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
