VALUES ('VLR-AO-010', 'Áo Dệt Kim Cổ Polo Sage Tinh Gọn', 'ao-det-kim-co-polo-sage-tinh-gon', 'Thiết kế cổ polo mềm trên nền dệt kim mịn tạo cảm giác chỉn chu nhưng vẫn trẻ trung và dễ gần. Phom áo ôm vừa phải giúp tôn dáng mà không gây gò bó, thích hợp cho phong cách smart casual. Gam Sage dịu mắt mang lại vẻ hiện đại và thanh lịch cho tủ đồ hằng ngày.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 510000, 720000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-det-kim-co-polo-sage-tinh-gon_sage_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass']::body_shape[], false, false, NULL, 'on_sale'::product_status)
