VALUES ('VLR-AO-011', 'Áo Blouse Organza Tay Bồng Champagne', 'ao-blouse-organza-tay-bong-champagne', 'Mẫu blouse organza với tay bồng nhẹ tạo hiệu ứng bay mềm và nữ tính nhưng vẫn giữ được vẻ thanh lịch. Phần thân áo được xử lý gọn gàng để tổng thể không quá cầu kỳ, phù hợp với phong cách soft romantic của Velura. Sắc Champagne giúp sản phẩm nổi bật theo hướng sang trọng, tinh tế và dễ ứng dụng trong các dịp hẹn hò hoặc tiệc nhẹ.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 620000, 820000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-blouse-organza-tay-bong-champagne_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
