VALUES ('VLR-AO-012', 'Áo Cape Top Lụa Sage Bay Nhẹ', 'ao-cape-top-lua-sage-bay-nhe', 'Thiết kế cape top với lớp phủ mềm rủ trên vai tạo chuyển động nhẹ và cảm giác thanh thoát khi mặc. Chất liệu lụa satin mờ giúp tổng thể trông sang nhưng không phô trương, phù hợp với tinh thần nữ tính hiện đại của Velura. Sắc Sage dịu mắt khiến mẫu áo vừa đủ khác biệt để mặc đi tiệc nhẹ, hẹn hò hoặc phối công sở theo hướng thời trang hơn.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 680000, 890000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-cape-top-lua-sage-bay-nhe_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
