VALUES ('VLR-AO-013', 'Áo Corset Mềm Phối Voan', 'ao-corset-mem-phoi-voan', 'Mẫu áo lấy cảm hứng từ corset nhưng được xử lý theo hướng mềm mại, thanh lịch với phần thân ôm nhẹ và lớp voan phủ tinh tế. Thiết kế giúp tạo điểm nhấn vòng eo mà không mang cảm giác quá sắc hay gò bó, rất phù hợp với hình ảnh nữ tính trưởng thành. Tông trầm ấm làm nổi bật vẻ sang trọng kín đáo, dễ ứng dụng cho tiệc tối, hẹn hò hoặc chụp lookbook.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 720000, 940000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-corset-mem-phoi-voan_cocoa_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-corset-mem-phoi-voan_terracotta__02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-corset-mem-phoi-voan_beige_03.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
