VALUES ('VLR-AO-014', 'Áo Cổ Yếm Drape Pearl Thanh Thoát', 'ao-co-yem-drape-pearl-thanh-thoat', 'Thiết kế cổ yếm kết hợp phần drape mềm ở thân áo mang đến cảm giác thanh thoát, nữ tính và có chút quyến rũ vừa đủ. Chất liệu satin rủ nhẹ giúp tổng thể trông mềm mại hơn trong chuyển động, đồng thời tạo hiệu ứng sang trọng cho những bản phối tối giản. Gam Pearl sáng nhã khiến sản phẩm phù hợp với các buổi hẹn tối, tiệc nhẹ hoặc những set đồ resort chic.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 650000, 860000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-co-yem-drape-pearl-thanh-thoat_pearl_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
