VALUES ('VLR-AO-015', 'Áo Sơ Mi Linen Pha Sand Thoáng Nhẹ', 'ao-so-mi-linen-pha-sand-thoang-nhe', 'Chất liệu linen pha mang lại cảm giác thoáng mát, mềm tay và phù hợp cho những ngày cần sự dễ chịu nhưng vẫn chỉn chu. Phom áo sơ mi cơ bản được tinh chỉnh vừa đủ để mặc đi làm, đi chơi hoặc phối theo phong cách nghỉ dưỡng thanh lịch. Sắc Sand trung tính giúp tổng thể nhẹ nhàng, tinh gọn và rất dễ ứng dụng.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 520000, 710000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-so-mi-linen-pha-sand-thoang-nhe_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel', 'Office']::VARCHAR(50)[], ARRAY['Rectangle', 'Apple']::body_shape[], false, false, NULL, 'on_sale'::product_status)
