VALUES ('VLR-AO-016', 'Áo Wrap Top Satin Quyến Nhẹ', 'ao-wrap-top-satin-quyen-nhe', 'Thiết kế wrap top ôm nhẹ vòng eo giúp tôn dáng một cách mềm mại và thanh lịch. Chất satin có độ bóng vừa phải mang lại vẻ trưởng thành, tinh tế mà không phô trương. Tông Cocoa ấm và sâu giúp sản phẩm nổi bật theo cách kín đáo, phù hợp với hẹn hò, tiệc tối hoặc những buổi gặp gỡ đặc biệt.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 670000, 870000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-wrap-top-satin-quyen-nhe_cocoa_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-wrap-top-satin-quyen-nhe_butter-yellow_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-wrap-top-satin-quyen-nhe_dusty-blue_03.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
