VALUES ('VLR-AO-019', 'Áo Sơ Mi Drape Mềm Slate Blue', 'ao-so-mi-drape-mem-slate-blue', 'Thiết kế sơ mi drape nhấn vào độ rủ mềm của chất liệu, tạo vẻ thanh lịch hiện đại và có chiều sâu hơn áo sơ mi cơ bản. Gam Slate Blue đem lại cảm giác điềm tĩnh, tinh tế và khác biệt vừa đủ trong tủ đồ công sở. Sản phẩm phù hợp với những bản phối tối giản nhưng vẫn muốn giữ dấu ấn nữ tính.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 690000, 890000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-so-mi-drape-mem_slate-blue_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Office', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass']::body_shape[], false, false, NULL, 'on_sale'::product_status)
