INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-AO-020', 'Áo Kiểu Xếp Ly Nhẹ Champagne Gold', 'ao-kieu-xep-ly-nhe-champagne-gold', 'Các đường xếp ly nhỏ ở thân áo tạo hiệu ứng mềm mại và giúp tổng thể trở nên nổi bật một cách tinh tế. Chất liệu nhẹ, có độ rủ vừa phải giúp sản phẩm phù hợp cho cả môi trường công sở lẫn những buổi gặp gỡ cần sự chỉn chu. Sắc Champagne Gold mang lại cảm giác sang trọng, nữ tính và rất đúng tinh thần soft luxury của Velura.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 630000, 830000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-kieu-xep-ly-nhe_champagne-gold_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
