VALUES ('VLR-AO-021', 'Áo Len Crochet Lệch Vai Tay Dài Oversize Trắng Ngà', 'ao-len-crochet-lech-vai-tay-dai-oversize-trang-nga', 'Áo len crochet đan móc thủ công với chất liệu sợi cotton mềm mại, thiết kế lệch vai (off-shoulder) gợi cảm khoe xương quai xanh. Tay áo dài oversize tạo hiệu ứng phồng nhẹ, bên trong có lớp lót camisole màu trắng chống lộ. Kiểu dáng lưới thoáng mát, mang lại vẻ đẹp nữ tính, bay bổng nhưng vẫn rất cá tính, phù hợp cho những buổi hẹn hò hay dạo phố về đêm.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 490000, 690000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-len-crochet-lech-vai-tay-dai-oversize-trang-nga_off-white_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Boho', 'Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
