VALUES ('VLR-AO-022', 'Áo Bất Đối Xứng Thắt Eo Cocoa', 'ao-bat-doi-xung-that-eo-cocoa', 'Thiết kế áo bất đối xứng với phần cổ cao mềm và chi tiết đai nhấn eo tạo hiệu ứng thanh mảnh, hiện đại. Chất vải có độ rũ vừa phải giúp tổng thể trông sang hơn nhưng vẫn giữ được sự thoải mái khi mặc. Gam Cocoa trầm ấm rất phù hợp với những set đồ thanh lịch dùng cho tiệc nhẹ, đi làm hoặc hẹn tối.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 620000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-bat-doi-xung-that-eo_cocoa_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Minimalist', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
