VALUES ('VLR-AO-023', 'Áo Cape Lệch Vai Ivory Mềm Rủ', 'ao-cape-lech-vai-ivory-mem-ru', 'Mẫu áo mang tinh thần nữ tính và sang trọng với phần tay cape buông mềm tạo chuyển động nhẹ khi mặc. Tông Ivory giúp tổng thể thanh thoát, dễ kết hợp cùng quần suông hoặc chân váy dài cho những dịp cần vẻ ngoài chỉn chu hơn thường ngày. Thiết kế đặc biệt phù hợp với các buổi tiệc, chụp ảnh hoặc hẹn hò tinh tế.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 690000, 930000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-cape-top-lua-sage-bay-nhe_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
