VALUES ('VLR-AO-024', 'Áo Dệt Gân Sage Tay Loe Nữ Tính', 'ao-det-gan-sage-tay-loe-nu-tinh', 'Áo dệt gân ôm nhẹ phần thân trên, kết hợp cổ mở và tay loe mềm tạo cảm giác thanh thoát, trẻ trung. Chất liệu co giãn nhẹ giúp mặc thoải mái mà vẫn giữ được phom dáng gọn gàng. Sắc Sage dịu mắt mang lại cảm giác nhẹ nhàng, rất hợp với những set đồ đi cà phê, du lịch hoặc hẹn hò ban ngày.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 540000, 760000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-det-gan-tay-loe-nu-tinh_sage_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Apple']::body_shape[], false, false, NULL, 'on_sale'::product_status)
