VALUES ('VLR-AO-025', 'Áo Croptop 2in1 Dệt Kim Sọc Nâu - Tube Top Kem', 'ao-croptop-2in1-det-kim-soc-nau-tube-top-kem', 'Áo croptop ôm sát thiết kế 2 trong 1 độc đáo: phần thân áo dạng tube top màu trắng kem ôm gọn, trong khi phần vai, ngực trên và tay áo được nối liền bằng lớp len dệt sọc ngang màu nâu đậm – nâu nhạt. Cổ tròn cao, tay dài ôm, chất len gân mềm mại. Dáng ngắn trên eo giúp tạo tỷ lệ chân dài lý tưởng. Phù hợp phong cách preppy, Y2K và soft girl mùa đông.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 520000, 750000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-croptop-2in1-det-kim-soc-nau-tube-top-kem_cream_01.png']::VARCHAR(255)[], ARRAY['Classic', 'Preppy', 'Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
