VALUES ('VLR-AO-026', 'Áo Crop Top Cổ Yếm Họa Tiết Loang & Bolero Tay Dài Đen', 'ao-crop-top-co-yem-hoa-tiet-loang-bolero-tay-dai-den', 'Set áo 2 lớp phong cách cyber streetwear, gồm áo crop top cổ yếm (halter neck) với họa tiết loang abstract xám đen trắng, điểm nhấn dây buộc chéo trang trí, kết hợp bolero tay dài đen ôm sát. Form crop trên eo tôn dáng, mang lại vẻ ngoài cá tính, bí ẩn và đầy sức hút cho những buổi tiệc tối hay dạo phố về đêm.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 550000, 750000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-crop-top-co-yem-hoa-tiet-loang-bolero-tay-dai-den_washed-black_01.png']::VARCHAR(255)[], ARRAY['Street', 'Minimalist', 'Sporty']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], true, true, NULL, 'on_sale'::product_status)
