VALUES ('VLR-AO-027', 'Áo kiểu sát nách viền ren thắt nơ', 'ao-kieu-sat-nach-vien-ren-that-no', 'Áo kiểu sát nách màu đen được thiết kế cổ V sâu, viền ren mềm và chi tiết dây thắt nơ ở thân trước. Chất liệu nhẹ, có độ rũ vừa phải, tạo cảm giác nữ tính nhưng vẫn phóng khoáng. Sản phẩm phù hợp để phối cùng quần linen, chân váy hoặc short cho phong cách resort casual.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 280000, 459000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-kieu-sat-nach-vien-ren-that-no_jet-black_1.png']::VARCHAR(255)[], ARRAY['Boho', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
