VALUES ('VLR-AO-028', 'Áo Sát Nách Cổ Cao Đen Logo Graphic Trắng', 'ao-sat-nach-co-cao-den-logo-graphic-trang', 'Áo sát nách cổ cao (sleeveless mock-neck) ôm vừa cơ thể, màu đen tuyền với logo graphic trắng ở chính giữa ngực. Chất liệu thun cotton co giãn mềm mịn, mang lại cảm giác thoải mái và tôn dáng. Thiết kế tối giản nhưng đầy cá tính, phù hợp phong cách streetwear Y2K, dễ dàng phối cùng chân váy hay quần ống rộng.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 420000, 620000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-sat-nach-co-cao-den-logo-graphic-trang_black_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Street', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
