VALUES ('VLR-AO-029', 'Áo lụa cổ yếm vạt dài olive', 'ao-lua-co-yem-vat-dai-olive', 'Áo lụa cổ yếm màu olive được thiết kế với phần cổ quấn chéo và vạt dài rũ nhẹ, tạo cảm giác mềm mại và sang trọng. Chất liệu lụa có độ bóng nhẹ, phù hợp với không khí mùa hè và các chuyến đi nghỉ dưỡng. Sản phẩm dễ phối cùng chân váy ngắn, quần suông hoặc sandal cao gót cho phong cách resort chic.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 340000, 559000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-lua-co-yem-vat-dai-olive_olive-satin_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
