VALUES ('VLR-AO-030', 'Áo yếm cổ V đính nút ivory', 'ao-yem-co-v-dinh-nut-ivory', 'Áo yếm màu ivory được thiết kế cổ V sâu, dây buộc sau cổ và hàng nút bọc ở thân trước tạo điểm nhấn nữ tính. Chất liệu vải mềm, đứng form nhẹ, giúp tôn phần vai và cổ một cách thanh thoát. Sản phẩm phù hợp để phối cùng quần trắng, chân váy hoặc phụ kiện ánh vàng cho phong cách resort chic.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 350000, 579000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-yem-co-v-dinh-nut-ivory_ivory-white_1.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
