VALUES ('VLR-AO-031', 'Áo Len Cropped Polo Sọc Ngang Gấu Rách', 'ao-len-cropped-polo-soc-ngang-gau-rach', 'Áo len dệt kim phong cách preppy grunge, thiết kế cropped ngắn trên eo với gấu rách tua (distressed) tạo điểm nhấn cá tính. Cổ polo bản lớn màu kem, hàng khuy ngắn với nút to bản. Họa tiết sọc ngang tông ivory, navy đậm và burgundy, tay dài oversize phủ tay. Sự kết hợp giữa vẻ ngoài học sinh thanh lịch và phá cách, hoàn hảo cho phong cách streetwear Hàn Quốc.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 520000, 730000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-len-cropped-polo-soc-ngang-gau-rach_ivory_01.png']::VARCHAR(255)[], ARRAY['Street', 'Classic', 'Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
