VALUES ('VLR-AO-032', 'Áo blouse boho thêu ren hồng pastel', 'ao-blouse-boho-theu-ren-hong-pastel', 'Áo blouse màu hồng pastel được thiết kế tay phồng, cổ buộc dây và các chi tiết thêu ren dọc thân áo tạo cảm giác nữ tính, mềm mại. Chất liệu vải nhẹ, thoáng, phù hợp với thời tiết mùa hè và các chuyến đi nghỉ dưỡng. Sản phẩm dễ phối cùng quần linen, chân váy hoặc sandal da cho phong cách boho casual.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 320000, 529000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-blouse-boho-theu-ren-hong-pastel_blush-pink_1.png']::VARCHAR(255)[], ARRAY['Boho', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
