VALUES ('VLR-AO-033', 'Áo satin hai dây cổ đổ champagne', 'ao-satin-hai-day-co-do-champagne', 'Áo satin hai dây màu champagne được thiết kế cổ đổ mềm mại, tạo cảm giác nữ tính và sang trọng. Chất liệu satin có độ bóng nhẹ, giúp bắt sáng tốt và phù hợp với các outfit đi chơi hoặc tiệc mùa hè. Sản phẩm dễ phối cùng chân váy mini, quần suông hoặc phụ kiện ánh vàng cho phong cách resort glam.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 340000, 559000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-satin-hai-day-co-do-champagne_pale-champagne_1.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
