VALUES ('VLR-AO-039', 'Áo Croset Vest Mocha', 'ao-croset-vest-mocha', 'Áo croset vest với thiết kế sang trọng với chất liệu nhung nâu mềm mại, cổ chữ V thanh lịch và hàng bốn nút vàng nổi bật phía trước. Phần gấu áo cắt nhọn tạo điểm nhấn tinh tế, mang hơi hướng vintage nhưng vẫn hiện đại và thời trang.', (SELECT category_id FROM category WHERE slug = 'ao' LIMIT 1), 650000, 860000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao/ao_ao-croset-vest_mocha_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
