VALUES ('VLR-DV-001', 'Đầm Tweed Hai Dây Thắt Nơ', 'dam-tweed-hai-day-that-no', 'Chiếc đầm hai dây dáng chữ A thanh lịch trên nền chất liệu vải tweed cao cấp. Thiết kế gây ấn tượng với điểm nhấn thắt eo bằng nơ lụa satin đen bản to giúp tôn vinh vóc dáng một cách hoàn hảo. Sắc hồng Rose Quartz ngọt ngào kết hợp họa tiết cổ điển mang lại vẻ ngoài kiêu kỳ cho các buổi tiệc hay hẹn hò.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 850000, 1250000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-hai-day-that-no_emerald_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-hai-day-that-no_rose-quartz_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
