VALUES ('VLR-DV-002', 'Đầm Mesh Tay Bồng Phối Nơ', 'dam-mesh-tay-bong-phoi-no', 'Thiết kế đầm dáng xòe ngắn quyến rũ phối cổ yếm lưới mesh xuyên thấu bay bổng. Điểm nhấn thắt nơ mảnh tinh tế ở cổ cùng phần tay bồng bo chun điệu đà mang lại diện mạo nữ tính, lãng mạn. Sắc xanh Mint Green dịu mát, ngọt ngào, là lựa chọn hoàn hảo cho các buổi tiệc hẹn hò nhẹ nhàng.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 820000, 1200000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-mesh-tay-bong-phoi-no_mint-green_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-mesh-tay-bong-phoi-no_sky-blue_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
