VALUES ('VLR-DV-003', 'Đầm Gấm Cung Điện Fake Two-Piece', 'dam-gam-cung-dien-fake-two-piece', 'Thiết kế đầm giả hai mảnh phong cách cung điện Pháp sang trọng với phần cổ sơ mi thắt nơ bản to tinh khôi. Thân váy chất liệu vải gấm cao cấp dệt họa tiết hoa hồng ánh bạc nổi bật trên nền đen quý phái, kết hợp cầu vai xếp bèo mềm mại. Form dáng xòe phồng bồng bềnh mang lại diện mạo kiêu kỳ, hoàn hảo cho các bữa tiệc tối lộng lẫy.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 950000, 1450000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-gam-cung-dien-fake-two-piece_midnight-silver_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-gam-cung-dien-fake-two-piece_sky-blue_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
