INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-004', 'Đầm Tweed Cổ Vuông Dáng Tầng', 'dam-tweed-co-vuong-dang-tang', 'Thiết kế đầm sát nách cổ vuông đầy kiêu kỳ trên nền chất liệu vải tweed cao cấp, nổi bật với tùng váy xếp tầng kiểu bánh kem bồng bềnh mang phong cách tiểu thư Academic và Old Money quý phái. Thân trước tạo điểm nhấn sang trọng bằng hai hàng khuy kim loại mạ vàng dập nổi tinh tế. Sắc trắng Pearl White thanh lịch tôn vinh diện mạo hoàn hảo cho các buổi tiệc hay sự kiện đặc biệt.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 820000, 1200000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-co-vuong-dang-tang_black_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-co-vuong-dang-tang_pearl-white_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
