VALUES ('VLR-DV-005', 'Đầm Yếm Xòe Thắt Nơ Lưng', 'dam-yem-xoe-that-no-lung', 'Thiết kế đầm cổ yếm dáng xòe ngắn mang đậm hơi hướng ngọt ngào, quyến rũ cho mùa hè. Điểm nhấn đắt giá tập trung ở phần lưng trần với nơ lụa satin màu trắng bản to thắt đuôi dài thướt tha, tạo hiệu ứng thị giác ấn tượng và nữ tính tuyệt đối. Sắc xám Pewter Gray phối trắng thanh lịch, thời thượng, vô cùng phù hợp cho các buổi tiệc ngoài trời, dạo phố hay những chuyến du lịch biển.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 880000, 1300000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-yem-xoe-that-no-lung_pewter-gray_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-yem-xoe-that-no-lung_sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Apple']::body_shape[], false, false, NULL, 'on_sale'::product_status)
