INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-006', 'Đầm Cổ Bèo Đính Hoa Vạt Lệch', 'dam-co-beo-dinh-hoa-vat-lech', 'Thiết kế đầm tay bồng mang phong cách Vintage Romantic pha trộn nét quý phái Old Money. Điểm nhấn nổi bật ở phần cổ phối bèo trắng bản to điệu đà, đính hoa hồng 3D cùng nơ ruy băng tinh tế. Tùng váy xòe xếp ly nhẹ với thiết kế vạt lệch (irregular hem) xếp lớp bồng bềnh, tạo nên những bước chuyển động vô cùng thướt tha và kiêu kỳ. Sắc xám Charcoal Gray thời thượng kết hợp trắng cổ điển là lựa chọn hoàn hảo cho mùa tựu trường hoặc các sự kiện sang trọng.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 1100000, 1650000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-beo-dinh-hoa-vat-lech_charcoal-gray_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-beo-dinh-hoa-vat-lech_sky-blue_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, true, NULL, 'on_sale'::product_status)
