INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-007', 'Đầm Cổ Cao Thắt Nơ Tùng Xếp Ly', 'dam-co-cao-that-no-tung-xep-ly', 'Thiết kế đầm sát nách dáng ngắn mang phong cách chỉn chu, thanh lịch pha chút nét cổ điển Preppy học đường. Điểm nhấn nổi bật ở phần cổ cao phối màu trắng tương phản, thắt nơ lụa bản to lệch bên điệu đà và kiêu kỳ. Thân dưới hạ eo phối tùng váy xếp ly bản lớn bồng bềnh, tạo form dáng trẻ trung và tôn vòng eo thon gọn. Sắc xanh đen Navy Blue quý phái, tôn da là lựa chọn hoàn hảo cho môi trường công sở, dạo phố hay các sự kiện nhẹ nhàng.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 680000, 980000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-cao-that-no-tung-xep-ly_cream_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-cao-that-no-tung-xep-ly_mint-green_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-cao-that-no-tung-xep-ly_mint-green_03.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-cao-that-no-tung-xep-ly_navy-blue_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
