VALUES ('VLR-DV-008', 'Đầm Tweed Sát Nách Đính Nơ Hồng', 'dam-tweed-sat-nach-dinh-no-hong', 'Thiết kế đầm sát nách cổ tròn rộng đầy ngọt ngào trên nền chất liệu vải tweed cao cấp, dày dặn lên form chuẩn. Điểm nhấn nữ tính mang đậm phong cách Coquette tiểu thư đến từ hàng khuy bọc màu hồng pastel nổi bật ở thân trước, kết hợp hoàn hảo cùng hai chiếc nơ hồng bản to đính điệu đà trên túi ốp hai bên hông. Form dáng chữ A xòe nhẹ giúp tôn trọn vòng eo thon gọn và mang lại diện mạo trẻ trung, thanh lịch cho các buổi hẹn hò, dạo phố hay tiệc trà.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 600000, 880000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-sat-nach-dinh-no-hong_sakura-black_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-sat-nach-dinh-no-hong_sakura-white_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Smart Casual']::VARCHAR(50)[], NULL, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Pear', 'Apple']::body_shape[], false, false, NULL, 'on_sale'::product_status)
