VALUES ('VLR-DV-009', 'Đầm Tweed Sát Nách Đính Hoa Hồng', 'dam-tweed-sat-nach-dinh-hoa-hong', 'Thiết kế đầm vest sát nách cổ vuông quyến rũ trên nền chất liệu tweed cao cấp đan sợi tinh tế. Thân trước tạo điểm nhấn với hàng khuy kim loại mạ vàng sang trọng dọc theo nẹp áo, kết hợp cùng hoa cài ngực dáng hồng 3D màu trắng phối nơ ruy băng đen thời thượng (có thể tháo rời). Chân váy dáng xòe ngắn phối viền satin trắng mang phong cách tiểu thư Coquette ngọt ngào và lãng mạn. Sắc hồng Sakura Pink dịu nhẹ tôn da, hoàn hảo cho các buổi tiệc hẹn hò, dạo phố mùa hè thu.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 750000, 1100000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-sat-nach-dinh-hoa-hong_black_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-sat-nach-dinh-hoa-hong_sakura-pink_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
