VALUES ('VLR-DV-010', 'Đầm Denim Hoa Nhí Đính Nơ Ngực', 'dam-denim-hoa-nhi-dinh-no-nguc', 'Đầm satin V-neck màu xanh dương thanh mát với thiết kế tối giản và hiện đại. Chất liệu satin mềm mại, phù hợp tiệc và đi chơi. Form dáng dài qua gối tôn dáng, dễ phối phụ kiện.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 820000, 1200000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-denim-hoa-nhi-dinh-no-nguc_denim-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-denim-hoa-nhi-dinh-no-nguc_sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Boho']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
