INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-011', 'Đầm Denim Khuy Tàu Sát Nách', 'dam-denim-khuy-tau-sat-nach', 'Thiết kế đầm denim sát nách cổ tròn mang hơi hướng sườn xám tân thời độc đáo, là sự giao thoa hoàn hảo giữa chất liệu denim cổ điển và nét đẹp truyền thống Á Đông. Điểm nhấn ấn tượng đến từ hàng khuy tàu (khuy tết dây) tinh tế dọc một bên thân trước, kết hợp cùng các đường rã rập chỉ nổi định hình form dáng corset tôn trọn vòng eo. Tùng váy dáng chữ A xòe nhẹ trẻ trung, mang lại diện mạo vừa cá tính, hiện đại vừa thanh lịch cho những buổi dạo phố, tiệc trà hay những chuyến du lịch.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 920000, 1350000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-denim-khuy-tau-sat-nach_classic-blue_01.png']::VARCHAR(255)[], ARRAY['Classic', 'Modern']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
