VALUES ('VLR-DV-012', 'Đầm Sát Nách Caro Cổ Lật', 'dam-sat-nach-caro-co-lat', 'Thiết kế đầm ngắn sát nách mang phong cách Preppy học đường pha chút nét cổ điển phóng khoáng. Nổi bật với họa tiết kẻ ô caro (plaid) tone xanh pastel nhẹ nhàng trên nền vải mềm mại, thoáng mát. Điểm nhấn độc đáo nằm ở phần cổ bẻ lật bất đối xứng, kết hợp hàng khuy cài chéo dọc thân và chi tiết bo chun gọn gàng tại vòng eo giúp tôn dáng tối đa. Phần chân váy xếp ly xòe nhẹ trẻ trung tạo nên tổng thể vừa thanh lịch, năng động, rất phù hợp cho những ngày đi học, đi làm hay dạo phố cuối tuần.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 880000, 1300000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-sat-nach-caro-co-lat_soft-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-sat-nach-caro-co-lat_sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Modern']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
