INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-013', 'Đầm Cổ Tim Tay Bồng Khuy Ngọc', 'dam-co-tim-tay-bong-khuy-ngoc', 'Thiết kế đầm ngắn chữ A mang đậm phong cách tiểu thư lãng mạn (Romantic French Style) đầy thanh lịch và ngọt ngào. Nổi bật với phần cổ tim (V-neck) đắp chéo mềm mại giúp tôn lên xương quai xanh quyến rũ, kết hợp cùng tay bồng nhẹ bo chun điệu đà. Điểm nhấn sang trọng nằm ở hàng khuy ngọc trai viền kim loại dập nổi tinh tế dọc thân trước và chi tiết rã rập eo cao giúp tôn vóc dáng thon gọn tuyệt đối. Sắc trắng kem Cream White dịu mắt, trang nhã là lựa chọn hoàn hảo cho các buổi hẹn hò lãng mạn, tiệc trà hay dạo phố ngày hè thu.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 980000, 1450000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-tim-tay-bong-khuy-ngoc_cream-white_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-co-tim-tay-bong-khuy-ngoc_sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
