INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-014', 'Đầm Tay Bồng Cổ Bèo Đính Hoa Hồng', 'dam-tay-bong-co-beo-dinh-hoa-hong', 'Thiết kế đầm ngắn mang đậm phong cách cổ điển lãng mạn pha chút Preppy học đường thời thượng. Nổi bật trên nền chất liệu vải cao cấp màu xám than (Charcoal Gray) chỉn chu là phần cổ lật màu trắng phối viền bèo dún (ruffle) điệu đà, kết hợp dải nơ ruy băng thắt dài đính hoa hồng 3D tinh tế làm điểm nhấn trung tâm. Thiết kế tay bồng ngắn trẻ trung kết hợp cùng tùng váy rã rập bất đối xứng xếp ly xòe nhẹ tạo hiệu ứng layer bồng bềnh, giúp tôn vóc dáng mảnh mai và mang lại diện mạo tiểu thư ngọt ngào cho những ngày đến trường, dạo phố hay tiệc trà.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 780000, 1150000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tay-bong-co-beo-dinh-hoa-hong_sakura-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tay-bong-co-beo-dinh-hoa-hong_sky-blue_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Romantic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
