INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-015', 'Đầm Tweed Trễ Vai Phối Nơ', 'dam-tweed-tre-vai-phoi-no', 'Thiết kế đầm ngắn trễ vai đầy lộng lẫy và kiêu sa, mang đậm phong cách tiểu thư đài các cho các bữa tiệc xa hoa. Sự kết hợp hoàn mỹ giữa chất liệu vải tweed ánh kim cao cấp, dày dặn định hình form chuẩn cùng phần ngực trễ vai bằng chất liệu lụa satin màu kem cao cấp mềm mại, xếp nếp khéo léo tạo thành một chiếc nơ bản to ôm trọn bờ vai trần quyến rũ. Thiết kế chiết eo corset tinh tế kết hợp tùng váy dáng chữ A xòe nhẹ giúp tôn trọn vóc dáng thanh mảnh và mang đến diện mạo sang trọng, cuốn hút tuyệt đối cho những buổi tiệc đêm, hẹn hò lãng mạn hay sự kiện đặc biệt.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 720000, 1050000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-tre-vai-phoi-no_black_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-tre-vai-phoi-no_ivory-cream_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Wedding']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
