INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-016', 'Đầm Kẻ Sọc Lệch Vai Đính Nơ', 'dam-ke-soc-lech-vai-no', 'Thiết kế đầm ngắn lệch vai mang đậm phong cách cổ điển lãng mạn và ngọt ngào, là sự lựa chọn hoàn hảo cho những buổi tiệc sinh nhật hay buổi hẹn hò. Điểm nhấn đắt giá nằm ở dải áo lệch vai được xếp nếp phồng tinh tế phối cùng chiếc nơ bản to kiêu sa bên vai trần quyến rũ. Thân váy ôm sát tinh tế nhờ kỹ thuật cắt may corset định hình tôn trọn vòng eo thon gọn, kết hợp cùng dải lụa quấn hông đính nơ điệu đà làm tăng thêm hiệu ứng bồng bềnh. Chân váy dập ly xòe nhẹ xếp tầng tinh nghịch tạo nên một tổng thể vừa trẻ trung, vừa sang trọng đầy lôi cuốn.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 1050000, 1550000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-ke-soc-lech-vai-no_mint-green_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-ke-soc-lech-vai-no_pink-plaid_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Birthday']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
