INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-017', 'Đầm Tweed Ngắn Tay Cổ Sơ Mi', 'dam-tweed-ngan-tay-co-so-mi', 'Thiết kế đầm giả set ngắn tay mang phong cách Preppy học đường pha chút nét sang trọng, đài các của tiểu thư Pháp. Được may trên nền chất liệu tweed dệt sợi cao cấp mềm mại với tone màu hồng Sakura Pink ngọt ngào, sản phẩm tạo điểm nhấn ấn tượng bằng phần cổ sơ mi và bo tay màu trắng tương phản tinh tế. Thân áo ôm nhẹ tôn dáng phối hàng khuy ngọc trai viền vàng sang trọng, đi kèm đai lưng bản vừa có khóa kim loại giúp định hình vòng eo thon gọn tối đa. Chân váy dập ly xòe nhẹ trẻ trung tạo hiệu ứng bồng bềnh chuyển động, rất phù hợp cho những ngày đi học, đi làm, dạo phố hay tiệc trà chiều.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 880000, 1300000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-ngan-tay-co-so-mi_sakura-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-tweed-ngan-tay-co-so-mi_sky-blue_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
