INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-018', 'Đầm Len Tăm Cổ Polo Viền', 'dam-len-tam-co-polo-vien', 'Thiết kế đầm len tăm (rib-knit) dài tay mang phong cách thể thao quý tộc (Old Money Aesthetic) đầy thanh lịch và thời thượng. Được dệt từ chất liệu len tăm mềm mại, co giãn lý tưởng giúp ôm trọn đường cong cơ thể một cách tinh tế. Sản phẩm tạo nét cuốn hút nhờ phần cổ Polo cổ điển phối hàng khuy cài nhỏ, kết hợp cùng chi tiết viền đen tương phản nổi bật ở cổ áo, nắp túi giả hai bên hông và gấu váy rủ nhẹ. Thiết kế tay áo loe nhẹ điệu đà cùng chân váy dáng xòe chữ A mang đến diện mạo vừa năng động, trẻ trung lại vừa kiêu sa, rất thích hợp cho những buổi dạo phố mùa thu đông, đi chơi golf, đi học hay gặp gỡ bạn bè.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 650000, 950000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-len-tam-co-polo-vien-den_ivory-white_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-len-tam-co-polo-vien-den_sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Modern']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
