INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-019', 'Đầm Hai Dây Khuy Bọc Đính Nơ Túi', 'dam-hai-day-khuy-boc-dinh-no-tui', 'Thiết kế đầm ngắn hai dây bản to với cổ chữ U khoét sâu vừa phải, mang đậm phong cách tiểu thư Coquette ngọt ngào và lãng mạn. Trên nền chất liệu vải cao cấp màu trắng kem (Cream White) dày dặn và đứng form, mặt trước của đầm được tạo điểm nhấn bằng hàng khuy bọc vải màu hồng pastel nhẹ nhàng. Sự kết hợp tinh tế tiếp tục xuất hiện ở hai chiếc túi ốp bên hông đính nơ lụa màu hồng bản vừa điệu đà. Form dáng chiết eo cao rã rập cùng tùng váy xòe nhẹ chữ A giúp che khuyết điểm vòng hông và tôn lên nét trẻ trung, trong trẻo, cực kỳ phù hợp cho các buổi tiệc sinh nhật, hẹn hò lãng mạn hay dạo phố ngày hè.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 7500000, 1500000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-hai-day-khuy-boc-dinh-no-tui_cream-sky-blue_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-hai-day-khuy-boc-dinh-no-tui_cream-white_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
