INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-020', 'Đầm Nhung Cúp Ngực Phối Nơ', 'dam-nhung-cup-ngurc-phoi-no', 'Thiết kế đầm ngắn cúp ngực đầy quyến rũ và bí ẩn trên nền chất liệu vải nhung (velvet) tăm cao cấp, mịn màng và có độ bóng nhẹ sang trọng. Sản phẩm tạo điểm nhấn thị giác ấn tượng bằng chi tiết nơ bản to bằng chất liệu satin màu trắng kem tương phản ôm trọn phần ngực áo, kết hợp cùng dải nơ dài rủ nhẹ tạo hiệu ứng thướt tha. Đường chiết eo cao corset kết hợp cùng tùng váy dáng chữ A xòe nhẹ giúp hack dáng, tôn vóc dáng đồng hồ cát quyến rũ. Đây là lựa chọn hoàn mỹ cho các buổi tiệc đêm sang trọng, sự kiện, tiệc cuối năm hay những buổi hẹn hò lãng mạn dưới ánh nến.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 9200000, 9200000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-nhung-cup-ngurc-phoi-no_classic-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_dam-nhung-cup-ngurc-phoi-no_classic-sakura-pink_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Wedding']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
