VALUES ('VLR-DV-025', 'Đầm Dạ Hội Cúp Ngực Dáng Xòe Phồng Tulle Xếp Tầng Pastel Pink', 'dam-da-hoi-cup-nguc-dang-xoe-phong-tulle-xep-tang-pastel-pink', 'Thiết kế đầm dạ hội đỉnh cao với phần thân trên corset xếp nếp tinh xảo tôn vòng một, kết hợp tùng váy dập phồng nhiều tầng từ chất liệu vải tulle cao cấp. Sắc hồng pastel dịu thướt tha tạo nên độ bồng bềnh lộng lẫy theo từng bước chuyển động.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 18500000, 18500000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_cup-nguc-dang-xoe-phong-tulle-xep-tang_pastel-pink_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], NULL, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
