INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-DV-026', 'Váy Tennis Xếp Ly Mini Cạp Cao Beige Kèm Thắt Lưng Nâu', 'vay-tennis-xep-ly-mini-cap-cao-beige-kem-that-lung-nau', 'Váy tennis mini phong cách preppy với form chữ A nhẹ, độ dài siêu ngắn, các ly xếp đều tạo chuyển động nhẹ nhàng. Eo cao kết hợp đi kèm thắt lưng bản vừa màu nâu chocolate, giúp định hình vòng eo và tăng vẻ thanh lịch. Màu beige nhạt dễ phối, mang lại vẻ ngoài nữ tính, trẻ trung và đúng điệu Y2K Hàn Quốc.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 480000, 690000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_vay-tennis-xep-ly-mini-cap-cao-beige-kem-that-lung-nau_beige_01.png']::VARCHAR(255)[], ARRAY['Preppy', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
