VALUES ('VLR-DV-027', 'Váy Midi Xẻ Tà Lace-Up Corset', 'vay-midi-xe-ta-lace-up-corset', 'Váy midi dáng chữ A nhẹ với cạp cao tôn dáng, điểm nhấn là hệ thống dây đan corset (lace-up) hai bên hông và xẻ tà cao một bên đùi gợi cảm. Chất liệu giả da/denim phủ wash tối mềm mại, gấu raw hem tua rua tinh tế. Thiết kế mang hơi hướng punk gothic pha chút quyến rũ, cực kỳ phù hợp cho phong cách đường phố hiện đại.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 620000, 860000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_vay-midi-xe-ta-lace-up-corset_washed-black_01.png']::VARCHAR(255)[], ARRAY['Street', 'Elegant', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
