VALUES ('VLR-DV-028', 'Váy Mini Xám Túi Hộp Bất Đối Xứng Phong Cách Y2K', 'vay-mini-xam-tui-hop-bat-doi-xung-phong-cach-y2k', 'Váy mini cạp cao dáng chữ A nhẹ với màu xám ghi (light heather grey) thời thượng. Điểm nhấn độc đáo là thiết kế bất đối xứng phía trước, túi hộp cargo lớn đắp ngoài một bên, khóa kéo kim loại trang trí và dây rủ dài tạo hiệu ứng Y2K. Chất liệu suiting fabric pha polyester đứng form, mềm mại. Sản phẩm mang hơi hướng utility fashion, cực kỳ cá tính và trẻ trung.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 590000, 820000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/dam-vay/dam-vay_vay-mini-xam-tui-hop-bat-doi-xung-phong-cach-y2k_light-grey_01.png']::VARCHAR(255)[], ARRAY['Street', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
