VALUES ('VLR-DV-029', 'Chân váy mini dáng chữ A ivory', 'chan-vay-mini-dang-chu-a-ivory', 'Chân váy mini màu ivory có phom chữ A gọn gàng, giúp tôn dáng và tạo cảm giác trẻ trung. Chất liệu vải dày vừa, bề mặt mịn, dễ phối với áo lụa, áo kiểu hoặc sơ mi mùa hè. Thiết kế tối giản giúp cân bằng các item nổi bật trong set đồ resort.', (SELECT category_id FROM category WHERE slug = 'dam-vay' LIMIT 1), 330000, 529000, ARRAY['set7(1).png']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
