INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-AK-001', 'Áo Blazer Lụa Satin', 'ao-blazer-lua-satin', 'Chiếc blazer được chế tác từ chất liệu lụa satin cao cấp, bề mặt mượt mà và óng ả. Thiết kế dáng suông thanh lịch với ve áo đơn giản và đường cắt tinh tế tôn dáng. Sản phẩm mang phong cách tối giản sang trọng, dễ dàng kết hợp từ công sở đến tiệc nhẹ.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 550000, 750000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-lua-satin_champagne_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-lua-satin_sage-green_02.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
