INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-AK-002', 'Áo Trench Coat Dáng Dài', 'ao-trench-coat-dang-dai', 'Áo trench coat dáng dài được may từ vải kaki pha cotton mềm mại, chống thấm nhẹ. Thiết kế hai hàng khuy, ve cổ lớn và đai thắt eo tạo dáng thanh thoát. Sản phẩm mang vẻ đẹp thanh lịch kiểu "tiểu thư Seoul", phù hợp cho những ngày se lạnh hay du lịch.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 600000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_trench-coat-dang-dai_warm-beige_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_trench-coat-dang-dai_dusty-rose_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
