VALUES ('VLR-AK-003', 'Áo Khoác Tweed Cropped', 'ao-khoac-tweed-cropped', 'Áo tweed cropped dáng ngắn với chất liệu vải tweed dệt pha sợi ánh kim sang trọng. Thiết kế form vuông vắn, cổ tròn, điểm nhấn là cúc kim loại mạ vàng tinh tế. Sản phẩm mang phong cách tiểu thư kiêu kỳ nhưng vẫn trẻ trung, dễ phối với quần jeans hay chân váy.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 500000, 700000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_tweed-cropped_blush-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_tweed-cropped_mint-cream_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
