INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-AK-004', 'Áo Cardigan Dài Dáng Rộng', 'ao-cardigan-dai-dang-rong', 'Cardigan dài dáng rộng được dệt từ len chunky mềm mại với họa tiết cable-knit nổi bật. Thiết kế cổ V sâu, vai rơi tự nhiên, cúc gỗ to bản tạo điểm nhấn. Sản phẩm mang phong cách "nàng thơ Hàn Quốc", ấm cúng và ngọt ngào cho những ngày se lạnh.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 450000, 650000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_cardigan-dai-dang-rong_cream_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_cardigan-dai-dang-rong_mauve_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Casual', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
