VALUES ('VLR-AK-005', 'Áo Vest Lông Faux', 'ao-vest-long-faux', 'Áo vest gilet không tay được làm từ chất liệu lông giả cao cấp, mềm mại và sang trọng. Thiết kế cổ tròn, dáng suông vừa phải, tạo cảm giác ấm áp và nữ tính. Sản phẩm mang phong cách thanh lịch, dễ dàng phối cùng áo sơ mi hoặc len cổ lọ.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 500000, 720000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_vest-long-faux_ivory_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_vest-long-faux_mocha_02.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
