VALUES ('VLR-AK-006', 'Áo Bomber Gió Dáng Lửng', 'ao-bomber-gio-dang-lung', 'Áo bomber gió dáng lửng với chất vải dù chống nước nhẹ, form phồng nhẹ đáng yêu. Thiết kế cổ bo, gấu bo chun, túi hộp hai bên và túi khóa kéo nhỏ trên tay áo. Sản phẩm mang phong cách năng động, trẻ trung, lý tưởng cho những ngày dạo phố hay đi chơi.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 420000, 620000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_bomber-gio-dang-lung_sand-beige_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_bomber-gio-dang-lung_dusty-blue_02.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Sporty']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Sport']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
