VALUES ('VLR-AK-008', 'Áo Sơ Mi Bomber', 'ao-so-mi-bomber', 'Thiết kế hybrid độc đáo giữa sơ mi và bomber, mang phong cách phá cách đầy cá tính. Chất liệu cotton pha mềm mại, cổ sơ mi điểm nhấn kết hợp với bo tay và bo gấu kiểu bomber. Sản phẩm dễ dàng phối cùng quần jean hay chân váy cho những set đồ đường phố ấn tượng.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 460000, 660000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_so-mi-bomber_terracotta-blush_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_so-mi-bomber_milk-tea_02.png']::VARCHAR(255)[], ARRAY['Street', 'Minimalist', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Office', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
