VALUES ('VLR-AK-009', 'Áo Hoodie Zip Dáng Rộng', 'ao-hoodie-zip-dang-rong', 'Áo hoodie zip dáng rộng với chất nỉ bông mềm mại, thoáng khí và dễ chịu. Thiết kế mũ trùm đầu rộng, dây rút kim loại, túi kangaroo phía trước tiện lợi. Sản phẩm mang phong cách đường phố Hàn Quốc, phù hợp cho những ngày năng động hay thư giãn tại nhà.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 380000, 550000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_hoodie-zip-dang-rong_cream_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_hoodie-zip-dang-rong_lilac_02.png']::VARCHAR(255)[], ARRAY['Casual', 'Sporty', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'School', 'Sport']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
