VALUES ('VLR-AK-010', 'Áo Gilet Phao Chần Bông', 'ao-gilet-phao-chan-bong', 'Áo gilet phao sát nách với chất vải dù chống nước, ruột bông nhẹ giữ ấm tốt. Thiết kế chần bông ngang, cổ đứng, khóa kéo hai chiều và túi hộp hai bên. Sản phẩm là item layer hoàn hảo, giữ ấm phần thân mà tay vẫn thoải mái cử động.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 400000, 580000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_gilet-phao-chan-bong_sage-green_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_gilet-phao-chan-bong_camel_02.png']::VARCHAR(255)[], ARRAY['Casual', 'Minimalist', 'Sporty']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'Sport']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
