VALUES ('VLR-AK-011', 'Áo Varsity Jacket', 'ao-varsity-jacket', 'Áo varsity jacket phong cách học đường với thân áo màu hồng phấn ngọt ngào và tay áo màu kem tương phản. Chất liệu vải dạ mềm, bo chun cổ tay và gấu áo, điểm nhấn là patch chữ thêu nổi trên ngực. Sản phẩm mang lại vẻ ngoài trẻ trung, năng động và đầy sức sống.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 520000, 720000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_varsity-jacket_blush-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_varsity-jacket_navy-mint_02.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'School', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
