VALUES ('VLR-AK-012', 'Áo Denim Jacket Oversize', 'ao-denim-jacket-oversize', 'Áo denim jacket oversize với chất vải denim mềm, rửa nhạt tạo hiệu ứng vintage bụi bặm. Thiết kế vai trễ, dáng rộng thùng thình, túi hộp lớn hai bên và khuy bấm kim loại. Sản phẩm mang phong cách đường phố cá tính, mặc được quanh năm và không bao giờ lỗi mốt.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 450000, 650000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-jacket-oversize_light-stonewash_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-jacket-oversize_onyx-black_02.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Minimalist']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
