VALUES ('VLR-AK-013', 'Áo Blazer Croptop', 'ao-blazer-croptop', 'Blazer croptop cắt ngắn ngang eo với chất vải tweed mềm mịn và form vuông vắn đứng dáng. Thiết kế đệm vai nhẹ, một khuy cài to bản, khoét cổ tròn tối giản. Sản phẩm tôn vòng eo và "ăn gian" chiều cao, phù hợp cho những cô nàng yêu thích phong cách Hàn Quốc hiện đại.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 530000, 730000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-croptop_blush_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-croptop_lavender_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
