VALUES ('VLR-AK-015', 'Áo Blazer Cardigan Hybrid', 'ao-blazer-cardigan-hybrid', 'Sự kết hợp tinh tế giữa blazer cổ điển và cardigan ấm áp, tạo nên item hybrid độc đáo. Chất liệu len pha mềm mại, ve áo notched, cúc một khuy ở eo kết hợp bo tay và bo gấu dạng cardigan. Sản phẩm vừa thanh lịch vừa thoải mái, phù hợp cho công sở và dạo phố.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 560000, 760000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-cardigan-hybrid_blush-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_blazer-cardigan-hybrid_pistachio_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
