VALUES ('VLR-AK-016', 'Áo Trench Denim Hybrid', 'ao-trench-denim-hybrid', 'Thiết kế đột phá kết hợp trench coat cổ điển với denim bụi bặm, tạo nên item hybrid thời thượng. Chất liệu denim mềm, form dáng trench coat dài qua gối với ve cổ lớn, đai thắt eo và cúc hai hàng. Sản phẩm mang vẻ đẹp sang trọng pha chút phá cách, lý tưởng cho những cô nàng yêu thích sự mới mẻ.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 580000, 780000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_trench-denim-hybrid_light-stonewash_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_trench-denim-hybrid_cream_02.png']::VARCHAR(255)[], ARRAY['Classic', 'Street', 'Minimalist']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
