VALUES ('VLR-AK-017', 'Áo Denim Bomber Hybrid', 'ao-denim-bomber-hybrid', 'Sự pha trộn hoàn hảo giữa denim jacket và bomber jacket, mang lại vẻ ngoài trẻ trung và cá tính. Chất liệu denim nhẹ với bo cổ, bo tay, bo gấu dạng bomber màu kem tương phản, khóa kéo trung tâm. Sản phẩm dễ phối cùng quần jogger hay chân váy cho set đồ đường phố sành điệu.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 490000, 690000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-bomber-hybrid_light-stonewash_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-bomber-hybrid_charcoal_02.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Sporty']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
