VALUES ('VLR-AK-019', 'Áo Denim Jacket Rách Oversize', 'ao-denim-jacket-rach-oversize', 'Áo denim jacket oversize với chi tiết rách tinh tế ở cổ tay và gấu áo, tạo nên vẻ đẹp bụi bặm pha chút phá cách. Chất liệu denim mềm mại, form rộng thùng thình, túi hộp lớn và khuy bấm kim loại. Sản phẩm mang phong cách đường phố năng động, dễ phối với nhiều loại trang phục.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 470000, 670000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-jacket-rach-oversize_cream_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_denim-jacket-rach-oversize_sage-green_02.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
