VALUES ('VLR-AK-020', 'Áo Cardigan Jacket Hybrid Rách', 'ao-cardigan-jacket-hybrid-rach', 'Áo cardigan jacket hybrid phá cách với chi tiết rách nhẹ tinh tế và form dáng oversized thoải mái. Chất liệu len dệt pha nỉ mềm, cổ tròn, cúc gỗ to bản, điểm nhấn là các sợi len tua rua nhẹ tại gấu và cổ tay. Sản phẩm vừa ấm cúng vừa thời trang, phù hợp cho những cô nàng yêu thích phong cách "soft girl" pha chút cá tính.', (SELECT category_id FROM category WHERE slug = 'ao-khoac' LIMIT 1), 490000, 690000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_cardigan-jacket-hybrid-rach_cream_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/ao-khoac/ao-khoac_cardigan-jacket-hybrid-rach_mocha_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Casual', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
