VALUES ('VLR-QU-001', 'Quần Short Linen Cạp Cao Dây Trắng', 'quan-short-linen-cap-cao-that-day-trang', 'Quần short linen cạp cao thiết kế tối giản với dây thắt nơ phía trước, tạo cảm giác thoải mái và nữ tính. Chất liệu linen thoáng mát, form suông nhẹ giúp che khuyết điểm hông và đùi hiệu quả. Phù hợp mặc hàng ngày, đi biển hoặc phối cùng áo croptop, sơ mi để tạo set đồ casual thanh lịch.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 390000, 590000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-linen-cap-cao-day-trang_ivory-white_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Brunch']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
