VALUES ('VLR-QU-002', 'Quần Culottes Linen Wrap Dài Cạp Cao', 'quan-culottes-linen-wrap-dai-cap-cao', 'Quần culottes linen dáng rộng dài với thiết kế wrap chéo tinh tế ở phần hông, tạo điểm nhấn thanh lịch và hiện đại. Chất liệu linen cao cấp thoáng mát, form suông nhẹ giúp che khuyết điểm tốt và mang lại cảm giác thoải mái. Gam màu Taupe trung tính sang trọng, dễ dàng phối với áo sơ mi, croptop hay blazer để tạo set đồ tối giản thanh lịch cho công sở hoặc đi chơi.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 520000, 720000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-culottes-linen-wrap-dai-cap-cao_olive-taupe_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-culottes-linen-wrap-dai-cap-cao_burgundy-wine_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
