VALUES ('VLR-QU-003', 'Quần Linen Ống Rộng Cạp Cao Thắt Dây', 'quan-linen-ong-rong-cap-cao-that-day', 'Quần linen ống rộng dáng palazzo với cạp cao và chi tiết dây thắt eo buộc nơ duyên dáng. Chất vải linen tự nhiên mềm mại, thoáng khí, mang lại cảm giác thoải mái và tôn dáng. Gam màu trung tính dễ phối đồ, phù hợp cho nhiều dịp từ công sở đến casual hàng ngày.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 480000, 680000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-linen-ong-rong-cap-cao-that-day_linen-cream_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
