VALUES ('VLR-QU-005', 'Quần Kaki Ống Rộng Cạp Cao Gấu Kẻ Sọc', 'quan-kaki-ong-rong-cap-cao-gau-ke-soc', 'Quần kaki ống rộng hiện đại với cạp cao, xếp ly phía trước và chi tiết gấu quần kẻ sọc tinh tế. Chất liệu vải dày dặn, giữ form tốt, mang lại vẻ ngoài thanh lịch nhưng vẫn trẻ trung. Dễ phối với áo sơ mi, blouse hoặc áo len để tạo set đồ công sở mang phong cách năng động tươi sáng.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 580000, 780000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-kaki-ong-rong-cap-cao-gau-ke-soc_espresso-brown_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-kaki-ong-rong-cap-cao-gau-ke-soc_champagne-beige_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Smart Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
