INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-QU-006', 'Quần Linen Ống Rộng Cạp Cao Kẻ Sọc Thắt Nơ', 'quan-linen-ong-rong-cap-cao-ke-soc-that-no', 'Quần linen ống rộng dáng palazzo với cạp cao kiểu paperbag xếp ly nhún xinh xắn và dây thắt nơ eo duyên dáng. Họa tiết kẻ sọc thanh lịch, chất vải linen thoáng mát, mềm mại giúp mang lại cảm giác thoải mái và tôn dáng. Thiết kế nữ tính, dễ phối cùng áo croptop, sơ mi hoặc blouse để tạo set đồ casual - romantic hiện đại.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 490000, 690000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-linen-ong-rong-cap-cao-ke-soc-that-no_sand-stripe_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-linen-ong-rong-cap-cao-ke-soc-that-no_mist-blue-stripe_1.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Classic', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Brunch']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
