VALUES ('VLR-QU-007', 'Quần Short Linen Cạp Cao Paperbag Gấu Cụp', 'quan-short-linen-cap-cao-paperbag-gau-cup', 'Quần short linen dáng suông với cạp cao kiểu paperbag nhún xinh xắn và gấu quần gập gọn gàng. Chất liệu linen tự nhiên thoáng mát, mềm mại, mang lại cảm giác nhẹ nhàng và thoải mái. Thiết kế tối giản dễ thương, dễ phối cùng áo croptop, blouse hoặc sơ mi để tạo set đồ casual nữ tính, phù hợp đi chơi, du lịch hoặc mặc hàng ngày.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 420000, 620000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-linen-cap-cao-paperbag-gau-cup_natural-linen_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-linen-cap-cao-paperbag-gau-cup_ivory-white_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Casual', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Brunch']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
