INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-QU-008', 'Quần Short Tây Cạp Cao Nút Vàng Gấu Cụp', 'quan-short-tay-cap-cao-nut-vang-gau-cup', 'Quần short tây cạp cao thanh lịch với chi tiết xếp ly phía trước và hàng nút vàng kim loại sang trọng. Form dáng suông nhẹ, gấu quần gập gọn gàng tạo vẻ chỉn chu. Chất liệu vải dày dặn giữ form tốt, phù hợp phối cùng áo sơ mi, blouse hoặc croptop để tạo set đồ công sở nữ tính hoặc casual thanh lịch.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 450000, 650000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-tay-cap-cao-nut-vang-gau-cup_midnight-navy_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Casual', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Office', 'Casual', 'Smart Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
