VALUES ('VLR-QU-009', 'Quần Ống Rộng Thắt Nơ Eo Phối Chỉ Trắng', 'quan-ong-rong-that-no-eo-phoi-chi-trang', 'Quần ống rộng dáng palazzo cao cấp với điểm nhấn là dây thắt nơ eo lớn dramatic và viền chỉ trắng tinh tế. Thiết kế cạp cao tôn dáng, form suông nhẹ giúp che khuyết điểm hiệu quả. Gam đen sang trọng, dễ phối cùng áo croptop, blouse hoặc áo khoác để tạo set đồ thanh lịch, hiện đại và đầy phong cách.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 590000, 790000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-ong-rong-that-no-eo-phoi-chi-trang_jet-black_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
