VALUES ('VLR-QU-010', 'Quần Jeans Ống Loe Cạp Cao Basic', 'quan-jeans-ong-loe-cap-cao-basic', 'Quần jeans ống loe dáng flare cổ điển với cạp cao chuẩn form, mang lại vẻ ngoài thanh lịch và tôn dáng. Chất denim dày dặn, bền màu, co giãn nhẹ. Thiết kế tối giản dễ phối đồ, phù hợp với nhiều phong cách từ casual, street style đến smart casual. Gam xanh đậm sang trọng, là item kinh điển không bao giờ lỗi mốt.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 650000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-jeans-ong-loe-cap-cao-basic_indigo-denim_1.jpg']::VARCHAR(255)[], ARRAY['Classic', 'Casual', 'Street']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'Weekend']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
