VALUES ('VLR-QU-011', 'Quần Jeans Ống Rộng Cạp Cao Wash Xám', 'quan-jeans-ong-rong-cap-cao-wash-xam', 'Quần jeans ống rộng dáng palazzo cao cấp với cạp cao chuẩn form và wash xám thời thượng. Chất denim dày dặn, mềm mại sau wash, giữ form tốt và mang lại cảm giác thoải mái. Thiết kế tối giản, dễ phối với nhiều kiểu áo từ croptop, sơ mi đến áo hoodie, phù hợp phong cách casual, street style và daily wear.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 680000, 880000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-jeans-ong-rong-cap-cao-wash-xam_washed-slate-denim_1.jpg']::VARCHAR(255)[], ARRAY['Casual', 'Street', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'Weekend']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
