VALUES ('VLR-QU-012', 'Quần Tây Ống Rộng Cạp Cao Basic Thanh Lịch', 'quan-tay-ong-rong-cap-cao-basic-thanh-lich', 'Quần tây ống rộng dáng palazzo cao cấp với cạp cao, xếp ly phía trước và form suông dài thanh lịch. Thiết kế tối giản chỉn chu, chất liệu vải dày dặn giữ phom tốt, mang lại vẻ ngoài sang trọng và chuyên nghiệp. Dễ phối cùng áo sơ mi, blouse, áo vest hoặc croptop để tạo set đồ công sở, tiệc nhẹ hoặc smart casual tinh tế.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 620000, 820000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-tay-ong-rong-cap-cao-basic-thanh-lich_ivory-cream_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-tay-ong-rong-cap-cao-basic-thanh-lich_jet-black_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party', 'Smart Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
