VALUES ('VLR-QU-013', 'Quần Tây Ống Rộng Tweed Cạp Cao Màu Xám', 'quan-tay-ong-rong-tweed-cap-cao-mau-xam', 'Quần tây ống rộng dáng palazzo cao cấp may từ chất liệu tweed textured cao cấp, mang lại vẻ ngoài sang trọng và ấm áp. Thiết kế cạp cao kèm xếp ly phía trước giúp tôn dáng và giữ form tốt. Gam xám trung tính thanh lịch, phù hợp phối với áo sơ mi, blouse lụa, áo len hoặc blazer để tạo set đồ công sở tinh tế hoặc smart casual mùa Thu Đông.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 680000, 880000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-tay-ong-rong-tweed-cap-cao-mau-xam_pearl-gray_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Smart Casual', 'Event']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
