VALUES ('VLR-QU-014', 'Quần Short Tây Cạp Cao Thắt Lưng', 'quan-short-tay-cap-cao-that-lung', 'Quần short tây cạp cao thanh lịch với chi tiết xếp ly phía trước và thắt lưng bản lớn (đi kèm) tạo điểm nhấn tinh tế. Form dáng suông nhẹ, gấu cúp gọn gàng, chất liệu vải dày dặn giữ form tốt. Thiết kế chỉn chu, nữ tính, dễ phối cùng áo sơ mi, blouse hoặc croptop để tạo set đồ công sở, smart casual hoặc đi chơi thanh lịch.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 480000, 680000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-tay-cap-cao-that-lung_mocha-corduroy_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-tay-cap-cao-that-lung_jet-black_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Smart Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
