VALUES ('VLR-QU-015', 'Quần Jeans Ống Loe Palazzo Cạp Cao Dark Wash', 'quan-jeans-ong-loe-palazzo-cap-cao-dark-wash', 'Quần jeans ống loe dáng palazzo cao cấp với cạp cao, xếp ly phía trước và form loe rộng dần về dưới cực kỳ tôn dáng. Chất denim dày dặn wash tối sang trọng, bền form, có túi hộp sau. Thiết kế hiện đại, thanh lịch nhưng vẫn giữ được nét casual, dễ phối với nhiều kiểu áo từ croptop, sơ mi đến áo khoác denim.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 720000, 920000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-jeans-ong-loe-palazzo-cap-cao-dark-wash_deep-indigo-denim_1.jpg']::VARCHAR(255)[], ARRAY['Casual', 'Street', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'Weekend']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
