VALUES ('VLR-QU-016', 'Quần Tây Ống Rộng Cạp Cao Gấu Cụp Thanh Lịch', 'quan-tay-ong-rong-cap-cao-gau-cup-thanh-lich', 'Quần tây ống rộng dáng palazzo cao cấp với cạp cao, xếp ly phía trước và gấu quần gập gọn gàng. Form suông dài thanh lịch, chất liệu vải dày dặn giữ phom tốt, mang lại vẻ ngoài chỉn chu và sang trọng. Dễ phối cùng áo sơ mi, blouse lụa hoặc áo vest để tạo set đồ công sở tinh tế hoặc smart casual hiện đại.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 650000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-tay-ong-rong-cap-cao-gau-cup-thanh-lich_smoky-taupe_1.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-tay-ong-rong-cap-cao-gau-cup-thanh-lich_cinnamon-brown_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Smart Casual', 'Event']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
