VALUES ('VLR-QU-017', 'Quần ống suông phối vạt bất đối xứng', 'quan-ong-suong-phoi-vat-bat-doi-xung', 'Quần ống suông màu đen được thiết kế với phần vạt phủ bất đối xứng ở eo, tạo điểm nhấn hiện đại và cá tính. Chất liệu vải dày dặn, đứng form, giúp tôn dáng và mang lại vẻ thanh lịch. Sản phẩm phù hợp với phong cách tối giản, sang trọng khi đi làm, đi tiệc hoặc phối đồ smart casual.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 620000, 799000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-ong-suong-phoi-vat-bat-doi-xung_jet-black_1.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
