VALUES ('VLR-QU-018', 'Quần short lưng cao xếp ly vải tweed', 'quan-short-lung-cao-xep-ly-vai-tweed', 'Quần short lưng cao màu nâu được thiết kế với phom dáng xếp ly nhẹ, tạo cảm giác thanh lịch và gọn dáng. Chất liệu vải tweed dày dặn, có bề mặt vân nhẹ giúp sản phẩm trông sang trọng hơn. Mẫu quần phù hợp với phong cách cổ điển, tối giản và dễ phối cùng áo sơ mi, áo len mỏng hoặc blazer.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 460000, 729000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-short-lung-cao-xep-ly-vai-tweed_mocha-brown_1.jpg']::VARCHAR(255)[], ARRAY['Classic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
