VALUES ('VLR-QU-019', 'Quần culottes lưng cao xếp ly', 'quan-culottes-lung-cao-xep-ly', 'Quần culottes lưng cao màu đen được thiết kế với phom ống rộng, đường xếp ly nhẹ phía trước giúp tạo cảm giác thanh lịch và gọn dáng. Chất liệu vải đứng form, mềm vừa phải, phù hợp để mặc cả ngày mà vẫn giữ vẻ chỉn chu. Sản phẩm dễ phối với áo sơ mi, áo kiểu hoặc blazer cho phong cách tối giản và smart casual.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 540000, 859000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-culottes-lung-cao-xep-ly_jet-black_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
