VALUES ('VLR-QU-020', 'Quần suông lưng cao phối đai khóa', 'quan-suong-lung-cao-phoi-dai-khoa', 'Quần suông lưng cao được thiết kế với phom ống rộng thanh lịch và chi tiết đai phối khóa tạo điểm nhấn hiện đại. Chất liệu vải dày vừa, đứng form và mềm mịn, giúp tôn dáng nhưng vẫn tạo cảm giác thoải mái khi mặc. Sản phẩm phù hợp với phong cách tối giản, thanh lịch, dễ phối cùng áo sơ mi, áo kiểu hoặc blazer cho môi trường công sở và các dịp thường ngày.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 590000, 929000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-suong-lung-cao-phoi-dai-khoa_chapagne-beige_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-suong-lung-cao-phoi-dai-khoa_jet-black_1.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-suong-lung-cao-phoi-dai-khoa_pearl-gray_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
