INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-QU-021', 'Quần Cargo Baggy Ống Rộng Cạp Cao Màu Kem Sữa', 'quan-cargo-baggy-ong-rong-cap-cao-mau-kem-sua', 'Quần cargo baggy phong cách đường phố với chất vải kaki pha cotton dày dặn, mềm mại nhưng giữ phom tốt. Thiết kế ống rộng suông (wide-leg) giúp che khuyết điểm và tạo cảm giác thoải mái. Điểm nhấn là hai túi hộp lớn ở hai bên đùi cùng cạp cao vừa phải tôn dáng. Gam màu kem sữa nhẹ nhàng dễ phối, cực kỳ hợp để diện cùng áo croptop hay áo len lệch vai.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 550000, 790000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-cargo-baggy-ong-rong-cap-cao-mau-kem-sua_cream-beige_01.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Rectangle', 'Pear']::body_shape[], false, false, NULL, 'on_sale'::product_status)
