VALUES ('VLR-QU-022', 'Quần Suông Linen Oatmeal Thanh Lịch', 'quan-suong-linen-oatmeal-thanh-lich', 'Thiết kế quần suông cạp cao với phom ống rộng rơi thẳng, mang lại cảm giác thanh thoát và chỉn chu cho tổng thể. Chất liệu linen pha có bề mặt tự nhiên, thoáng nhẹ nhưng vẫn đủ đứng phom để phù hợp với những set đồ thanh lịch, nữ tính. Tông Oatmeal trung tính giúp mẫu quần dễ phối cùng các gam nâu, ivory, champagne hoặc sage cho những dịp đi làm, hẹn hò hay tiệc nhẹ.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 760000, 1020000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-suong-linen-oatmeal-thanh-lich_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Pear', 'Apple']::body_shape[], false, false, NULL, 'on_sale'::product_status)
