VALUES ('VLR-QU-023', 'Quần Suông Ống Rộng Ivory Thanh Lịch', 'quan-suong-ong-rong-ivory-thanh-lich', 'Quần suông cạp cao với phom ống rộng rơi thẳng giúp tổng thể trông dài và thanh thoát hơn. Chất vải đứng phom vừa phải nhưng vẫn giữ được sự mềm mại, phù hợp để phối cùng áo kiểu, áo ôm hoặc gilet trong nhiều dịp khác nhau. Tông Ivory sáng thanh lịch giúp món đồ dễ ứng dụng từ đi làm đến tiệc tối nhẹ nhàng.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 720000, 980000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-suong-ong-rong-ivory-thanh-lich_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party', 'Casual']::VARCHAR(50)[], ARRAY['Rectangle', 'Hourglass', 'Pear', 'Apple', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
