VALUES ('VLR-QU-024', 'Quần linen ống rộng lưng thun dây rút', 'quan-linen-ong-rong-lung-thun-day-rut', 'Quần linen ống rộng màu kem có thiết kế lưng thun phối dây rút, tạo cảm giác thoải mái và dễ mặc. Chất liệu linen nhẹ, thoáng, bề mặt tự nhiên phù hợp với thời tiết mùa hè. Phom quần suông dài giúp outfit trông thanh lịch nhưng vẫn giữ tinh thần nghỉ dưỡng.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 420000, 699000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-linen-ong-rong-lung-thun-day-rut_linen-cream_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Boho', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
