VALUES ('VLR-QU-025', 'Quần trắng ống rộng lưng cao', 'quan-trang-ong-rong-lung-cao', 'Quần ống rộng màu trắng có thiết kế lưng cao, phom suông dài giúp tạo cảm giác thanh lịch và kéo dài dáng. Chất liệu denim/vải dày vừa, đứng form nhưng vẫn dễ mặc trong các outfit mùa hè. Mẫu quần phù hợp với áo yếm, áo kiểu hoặc sơ mi nhẹ cho phong cách casual chic.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 500000, 799000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-trang-ong-rong-lung-cao_pure-white_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
