VALUES ('VLR-QU-026', 'Quan jeans ong cuc rong xep ly light wash', 'quan-jeans-ong-cuc-rong-xep-ly-light-wash', 'Quần jeans dáng balloon/wide-leg cực rộng với cạp cao và nhiều đường xếp ly lớn phía trước, tạo khối phồng nhẹ ở đùi rồi đổ suông rộng tới gấu. Chất denim light wash vintage, mềm mại, trọng lượng trung bình, mang cảm hứng Japanese streetwear và Y2K. Kiểu dáng tôn dáng, kéo dài chân tối đa, cực kỳ hợp với áo cropped để tạo tỷ lệ cơ thể hoàn hảo.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 680000, 920000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-jeans-ong-cuc-rong-xep-ly-light-wash_light-wash_01.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Minimalist']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, '(để trống)', 'on_sale'::product_status)
