VALUES ('VLR-QU-027', 'Quần linen ống rộng màu kem', 'quan-linen-ong-rong-mau-kem', 'Quần linen ống rộng màu kem có thiết kế lưng thun phối dây rút, mang lại cảm giác thoải mái khi di chuyển. Chất liệu linen nhẹ, bề mặt tự nhiên và thoáng mát, rất phù hợp với các outfit mùa hè. Phom quần suông dài giúp tổng thể trang phục trông thanh lịch nhưng vẫn giữ được tinh thần nghỉ dưỡng.', (SELECT category_id FROM category WHERE slug = 'quan' LIMIT 1), 420000, 699000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/quan/quan_quan-linen-ong-rong-mau-kem_linen-cream_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Boho', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
