VALUES ('VLR-GD-001', 'Giày Sandals Quai Ngang Đế Thấp', 'giay-sandals-quai-ngang-de-thap', 'Đôi sandals thiết kế quai ngang thanh mảnh kết hợp quai cổ chân nữ tính. Chất liệu da lộn mềm mại phối cùng gót vuông thấp mang lại sự êm ái tối đa khi di chuyển. Phong cách tối giản, dễ dàng mix-match từ công sở đến dạo phố ngày thường.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-quai-ngang-de-thap_matte-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-quai-ngang-de-thap_fresh-mint_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-quai-ngang-de-thap_pastel-blue_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
