VALUES ('VLR-GD-002', 'Giày Cao Gót Slingback Mũi Nhọn Da Bóng', 'giay-cao-got-slingback-mui-nhon-da-bong', 'Thiết kế giày slingback mũi nhọn kiêu kỳ được hoàn thiện trên nền chất liệu da bóng cao cấp thu hút mọi ánh nhìn. Phần quai hậu mảnh mai kết hợp quai ngang khóa cài tinh tế giúp ôm chân cố định, đi cùng gót kitten heel thanh lịch dễ dàng di chuyển. Sản phẩm mang phong cách quý phái, là điểm nhấn hoàn hảo cho các bộ trang phục trang trọng.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 700000, 900000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-slingback-mui-nhon-da-bong_ice-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-slingback-mui-nhon-da-bong_burgundy_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
