INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-GD-003', 'Giày Thể Thao Ballet Core Buộc Dây', 'giay-the-thao-ballet-core-buoc-day', 'Sự giao thoa độc đáo giữa phong cách thể thao năng động và xu hướng Ballet Core điệu đà, nữ tính. Giày được hoàn thiện bằng chất liệu vải dệt họa tiết hoa chìm sang trọng, điểm nhấn là dải dây ruy-băng satin thắt nơ cổ chân duyên dáng. Thiết kế đế gum bám dính tốt, mang lại sự nhẹ nhàng, êm ái và định hình phong cách cá tính cho người mặc.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 500000, 700000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-the-thao-ballet-core-buoc-day_blossom-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-the-thao-ballet-core-buoc-day_dusty-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-the-thao-ballet-core-buoc-day_sand-shell_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
