INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-GD-004', 'Giày Búp Bê Đế Bệt Buộc Dây Cổ Chân', 'giay-bup-be-de-bet-buoc-day-co-chan', 'Kiểu dáng giày búp bê đế bệt kinh điển được làm mới với phần dây quấn cổ chân đầy nữ tính và duyên dáng. Chất liệu da lộn mềm mịn ôm sát phom chân tạo cảm giác thoải mái tuyệt đối khi mang cả ngày dài. Thiết kế mang phong cách nhẹ nhàng, dễ dàng kết hợp cùng các kiểu váy voan, chân váy xòe điệu đà.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 600000, 800000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-de-bet-buoc-day-co-chan_baby-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-de-bet-buoc-day-co-chan_sage-mint_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-de-bet-buoc-day-co-chan_cream-sand_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-de-bet-buoc-day-co-chan_soft-rose_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office', 'Travel']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
