VALUES ('VLR-GD-005', 'Giày Ankle Boots Thắt Dây Mũi Vuông', 'giay-ankle-boots-that-day-mui-vuong', 'Thiết kế ankle boots mũi vuông mang đậm hơi hướng thời trang hiện đại và thời thượng. Chất liệu da cao cấp mềm mại kết hợp cùng chi tiết thắt dây đan cá tính và khóa kéo hông tiện lợi khi mang. Phần gót vuông thô chắc chắn mang lại vẻ ngoài vừa mạnh mẽ, vừa tôn dáng, dễ dàng kết hợp với quần jeans hoặc chân váy dài dạo phố.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 450000, 650000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-ankle-boots-that-day-mui-vuong_pure-white_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-ankle-boots-that-day-mui-vuong_matte-black_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
