VALUES ('VLR-GD-006', 'Giày Boots Mũi Nhọn Thắt Dây Cổ Điển', 'giay-boots-mui-nhon-that-day-co-dien', 'Đôi boots cổ lửng với thiết kế mũi nhọn thời thượng cùng chi tiết dây buộc đan chéo mang lại vẻ đẹp cổ điển đầy cuốn hút. Chất liệu da cao cấp mềm mại, kết hợp cùng gót trụ chắc chắn tạo cảm giác thoải mái khi di chuyển. Phụ kiện hoàn hảo để phối cùng quần ống rộng hoặc chân váy midi cho vẻ ngoài thanh lịch.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 400000, 600000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-boots-mui-nhon-that-day-co-dien_cream-sand_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-boots-mui-nhon-that-day-co-dien_slate-blue_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
