VALUES ('VLR-GD-008', 'Giày Mary Jane Thể Thao Đế Bệt', 'giay-mary-jane-the-thao-de-bet', 'Sự kết hợp độc đáo giữa nét năng động của giày thể thao và vẻ mềm mại từ phom dáng Mary Jane kinh điển. Thân giày hoàn thiện bằng chất liệu da lộn phối màu pastel thời thượng, nổi bật với hệ thống quai đan chéo co giãn ôm gọn bàn chân. Phần đế bệt bằng cao su mềm dẻo mang lại cảm giác êm ái tối đa, lý tưởng cho những cô nàng ưa dịch chuyển mà vẫn muốn giữ vẻ nữ tính.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 899999, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-mary-jane-the-thao-de-bet_pastel-teal_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-mary-jane-the-thao-de-bet_blossom-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-mary-jane-the-thao-de-bet_sand-shell_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
