VALUES ('VLR-GD-009', 'Giày Cao Gót Slingback Mũi Nhọn Quai Chéo', 'giay-cao-got-slingback-mui-nhon-quai-cheo', 'Thiết kế giày slingback mũi nhọn thời thượng kết hợp cùng hệ thống quai mảnh đan chéo tinh tế tạo điểm nhấn thanh thoát cho mu bàn chân. Chất liệu da lì cao cấp mượt mà phối cùng gót kitten heel thanh lịch giúp tôn dáng nhẹ nhàng mà vẫn đảm bảo sự thoải mái khi di chuyển. Phong cách hiện đại và trang nhã, dễ dàng ứng dụng cho cả môi trường công sở lẫn các buổi hẹn hò.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 999000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-slingback-mui-nhon-quai-cheo_sage-green_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-slingback-mui-nhon-quai-cheo_matte-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-slingback-mui-nhon-quai-cheo_pure-white_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office', 'Party']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
