VALUES ('VLR-GD-010', 'Giày Cao Gót Lụa Satin Thắt Nơ Cổ Chân', 'giay-cao-got-lua-satin-that-no-co-chan', 'Thiết kế cao gót d''Orsay mũi nhọn đầy kiêu kỳ được phủ lớp vải lụa satin cao cấp đem lại độ bóng bẩy, sang trọng dưới mọi ánh nhìn. Điểm nhấn đắt giá là phần quai ruy-băng bản lớn quấn quanh cổ chân, dễ dàng tạo kiểu thắt nơ duyên dáng mang đậm hơi hướng lãng mạn, ngọt ngào. Chiều cao gót kitten heel vừa vặn nâng dáng nhẹ nhàng, rất thích hợp làm điểm nhấn cho những bộ váy đầm thướt tha.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 955000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-lua-satin-that-no-co-chan_blossom-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-lua-satin-that-no-co-chan_pure-white_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office', 'Party']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
