VALUES ('VLR-GD-011', 'Giày Sandals Xỏ Ngón Quai Mảnh Buộc Dây', 'giay-sandals-xo-ngon-quai-manh-buoc-day', 'Thiết kế sandals xỏ ngón đầy phóng khoáng với phần mũi vuông hiện đại phối cùng hệ thống quai dây mảnh thanh thoát. Chất liệu da mềm mượt kết hợp phần dây buộc cổ chân linh hoạt, dễ dàng điều chỉnh tạo điểm nhấn thu hút cho đôi chân. Kiểu dáng đế bệt nhẹ nhàng và êm ái, là phụ kiện không thể thiếu cho những chuyến du lịch hay những buổi dạo phố ngày hè đầy tự do.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 890000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-xo-ngon-quai-manh-buoc-day_chestnut-brown_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-xo-ngon-quai-manh-buoc-day_matte-black_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
