VALUES ('VLR-GD-012', 'Giày Cao Gót Mary Jane Phối Màu Cap-Toe', 'giay-cao-got-mary-jane-phoi-mau-cap-toe', 'Thiết kế giày Mary Jane mang đậm tinh thần hoài cổ đầy sang trọng với điểm nhấn mũi tròn bọc da cap-toe phối màu tương phản thời thượng. Chất liệu da cao cấp mềm mại kết hợp cùng thiết kế gót vuông thô thấp và quai ngang mảnh giúp cố định bàn chân chắc chắn trong từng bước đi. Phom dáng mang phong cách tiểu thư đài các, cực kỳ lý tưởng khi phối cùng váy ngắn dạo phố hoặc trang phục công sở trang nhã.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 890000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-mary-jane-phoi-mau-cap-toe_cream-black_01.png']::VARCHAR(255)[], ARRAY['Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
