VALUES ('VLR-GD-013', 'Giày Búp Bê Mary Jane Da Lộn Đế Bệt', 'giay-bup-be-mary-jane-da-lon-de-bet', 'Kiểu dáng giày búp bê Mary Jane kinh điển sở hữu phom dáng thon gọn ôm chân nhẹ nhàng đầy thanh lịch. Hoàn thiện từ chất liệu da lộn cao cấp có bề mặt mịn màng mang tông màu xanh rêu khói thời thượng và lãng mạn. Thiết kế đế bệt êm ái cùng quai ngang mảnh tinh tế giúp bạn tự tin sải bước thoải mái suốt ngày dài năng động.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 650000, 890000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-mary-jane-da-lon-de-bet_sage-khaki_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-mary-jane-da-lon-de-bet_warm-camel_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-mary-jane-da-lon-de-bet_baby-blue_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office', 'Travel']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
