VALUES ('VLR-GD-016', 'Guốc Cao Gót Mule Hở Mũi Đính Nơ', 'guoc-cao-got-mule-ho-mui-dinh-no', 'Thiết kế guốc mule cao gót hở mũi mang lại vẻ đẹp phóng khoáng, nhẹ nhàng nhưng không kém phần thanh lịch cho phái đẹp. Thân giày hoàn thiện từ chất liệu da lì cao cấp mượt mà, tạo điểm nhấn ngọt ngào bằng chi tiết nơ thắt xinh xắn và đường uốn lượn tinh tế trên quai ngang. Chiều cao gót kitten heel thanh mảnh vừa vặn nâng dáng, kết hợp thiết kế xỏ chân tiện lợi biến đôi guốc này thành phụ kiện lý tưởng cho cả ngày đi làm bận rộn hay những buổi trà chiều dạo phố cùng bạn bè.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 500000, 800000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_guoc-cao-got-mule-ho-mui-dinh-no_off-white_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_guoc-cao-got-mule-ho-mui-dinh-no_matte-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_guoc-cao-got-mule-ho-mui-dinh-no_mellow-yellow_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
