VALUES ('VLR-GD-017', 'Giày Cao Gót Phối Lưới Đính Hoa 3D Thủ Công', 'giay-cao-got-phoi-luoi-dinh-hoa-3d-thu-cong', 'Tuyệt tác giày cao gót cổ thiên nga được kiến tạo từ chất liệu vải lưới mesh xuyên thấu thêu hoa tinh xảo kết hợp cùng các dải lụa satin mềm mại. Bề mặt mui giày được đính kết hạt cườm thủ công tạo hiệu ứng lấp lánh như pha lê, điểm xuyết bằng bông hoa lụa 3D kiêu sa nơi mũi nhọn quý phái. Thiết kế quai ôm cổ chân mảnh mai cùng gót nhọn thanh thoát cao vút, biến đôi giày thành sự lựa chọn tối thượng nâng tầm vẻ đẹp lộng lẫy cho các nàng dâu trong ngày cưới hay quý cô tại những dạ tiệc hoàng gia.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 700000, 999000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-phoi-luoi-dinh-hoa-3d-thu-cong_baby-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-phoi-luoi-dinh-hoa-3d-thu-cong_baby-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-phoi-luoi-dinh-hoa-3d-thu-cong_mint-green_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
