VALUES ('VLR-GD-018', 'Giày Cao Gót Pumps Mũi Nhọn Phối Khóa Đá', 'giay-cao-got-pumps-mui-nhon-phoi-khoa-da', 'Thiết kế giày cao gót kinh điển được làm mới với đường cắt khoét dọc thân giày vô cùng uyển chuyển và ôm dáng. Sức hút của đôi giày tập trung ở phần quai da mảnh vắt chéo nơi mũi nhọn phối cùng chiếc khóa tròn đính kết đá tinh xảo tạo hiệu ứng lấp lánh sang trọng. Chất liệu da cao cấp mềm mại kết hợp cùng gót nhọn thanh thoát giúp tôn vinh trọn vẹn nét kiêu sa, lịch lãm của các quý cô hiện đại.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 750000, 985000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-pumps-mui-nhon-phoi-khoa-da_sage-mint_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-pumps-mui-nhon-phoi-khoa-da_matte-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-pumps-mui-nhon-phoi-khoa-da_deep-burgundy_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-pumps-mui-nhon-phoi-khoa-da_off-white_01.png']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
