VALUES ('VLR-GD-019', 'Giày Sandals Gót Vuông Quai Cổ Chân Bản Lớn', 'giay-sandals-got-vuong-quai-co-chan-ban-lon', 'Thiết kế sandals gót vuông năng động sở hữu phần quai ngang hở mũi thoáng đãng kết hợp cùng quai cổ chân bản lớn thời thượng. Hoàn thiện từ chất liệu da lộn mềm mịn mang tông màu xanh pastel dịu mát, tạo cảm giác êm ái và nhẹ nhàng cho bàn chân. Kiểu dáng gót vuông thô chắc chắn có độ cao vừa phải, mang đến sự tự tin và thoải mái tuyệt đối cho các cô nàng khi di chuyển liên tục suốt cả ngày.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 675000, 899000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-got-vuong-quai-co-chan-ban-lon_baby-blue_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-got-vuong-quai-co-chan-ban-lon_pale-mint_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-got-vuong-quai-co-chan-ban-lon_baby-pink_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-got-vuong-quai-co-chan-ban-lon_matte-black_01.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sandals-got-vuong-quai-co-chan-ban-lon_off-white_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office']::VARCHAR(50)[], NULL, false, true, NULL, 'on_sale'::product_status)
