VALUES ('VLR-GD-023', 'Sandal Gót Mảnh Cocoa Thanh Lịch', 'sandal-got-manh-cocoa-thanh-lich', 'Mẫu sandal quai mảnh với gót cao thanh giúp tổng thể trông nhẹ và nữ tính hơn, đồng thời dễ kết hợp với quần suông hoặc váy midi. Gam Cocoa trầm ấm tạo cảm giác sang trọng, phù hợp với các set đồ dự tiệc nhẹ hoặc hẹn tối. Đây là kiểu giày lý tưởng cho phong cách thanh lịch hiện đại, không quá phô trương nhưng vẫn đủ nổi bật.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 590000, 810000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_sandal-got-manh-cocoa-thanh-lich_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
