VALUES ('VLR-GD-025', 'Giày Cao Gót Quai Mảnh Onyx Thanh Mảnh', 'giay-cao-got-quai-manh-onyx-thanh-manh', 'Mẫu giày cao gót quai mảnh với phom mũi nhọn hở trước nhẹ và phần quai cổ chân thanh thoát giúp tổng thể trông sắc sảo, hiện đại hơn. Gam Onyx đen sâu tạo độ tương phản tinh tế khi phối cùng quần trắng, xanh navy hoặc các tông trung tính, rất phù hợp cho những set đồ dự tiệc, hẹn tối hay công sở thanh lịch. Thiết kế vừa tôn dáng vừa giữ được vẻ sang trọng tối giản đúng tinh thần Soft Ceremony.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 640000, 880000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-cao-got-quai-manh-onyx-thanh-manh_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
