VALUES ('VLR-GD-026', 'Sandal Sage Quai Mảnh Gót Thấp', 'sandal-sage-quai-manh-got-thap', 'Đôi sandal quai mảnh với gót thấp vừa phải mang lại cảm giác thanh thoát nhưng vẫn dễ di chuyển và thoải mái khi mặc lâu. Tông Sage dịu nhẹ tạo điểm nhấn tinh tế cho các set đồ màu kem, trắng ngà hoặc beige. Phù hợp với những buổi cà phê, hẹn hò ban ngày hoặc chuyến đi ngắn cuối tuần.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 520000, 730000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_sandal-sage-quai-manh-got-thap_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
