VALUES ('VLR-GD-027', 'Slingback Mũi Nhọn Cocoa Tối Giản', 'slingback-mui-nhon-cocoa-toi-gian', 'Thiết kế slingback mũi nhọn với phần gót thanh mảnh tạo cảm giác hiện đại, gọn gàng và thanh lịch. Màu Cocoa giúp đôi giày dễ phối cùng các set đồ trắng kem, ivory hoặc nâu trầm theo tinh thần tối giản sang trọng. Đây là lựa chọn phù hợp cho tiệc tối, hẹn hò hoặc những dịp cần vẻ ngoài trưởng thành hơn.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 610000, 840000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_slingback-mui-nhon-cocoa-toi-gian_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
