VALUES ('VLR-GD-028', 'Boots Tuyết Lót Lông Dây Rút Viền Lông Cream', 'boots-tuyet-lot-long-day-rut-vien-long-cream', 'Boots tuyết cổ mid-calf với chất liệu vải chống nước, lót lông dày giữ ấm tối đa. Thiết kế dây rút phía trước tiện điều chỉnh, viền lông mềm ở cổ giày tạo điểm nhấn đáng yêu. Đế chống trượt an toàn khi di chuyển. Màu off-white/cream mang lại cảm giác ấm áp, dễ thương, phù hợp với outfit đi trượt tuyết hay winter resort, đồng thời rất hợp phong cách Korean soft girl.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 600000, 850000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-boots-tuyet-lot-long-cao-co-mau-kem_off-white_01.png']::VARCHAR(255)[], ARRAY['Sporty', 'Casual', 'Romantic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Sport']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
