VALUES ('VLR-GD-029', 'Giày Mary Jane Platform Đế Lông Đen', 'giay-mary-jane-platform-de-long-den', 'Giày Mary Jane platform với đế cực dày răng cưa, hai quai khóa kim loại chắc chắn và phần đế phủ lông nhân tạo mềm mại màu đen. Phom dáng Harajuku dark kawaii, kết hợp tất cổ trung đen tạo nên vẻ ngoài vừa dễ thương vừa cá tính. Là item hoàn hảo để nâng tầm phong cách gothic Y2K.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 720000, 990000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-mary-jane-platform-de-long-den_jet-black_01.png']::VARCHAR(255)[], ARRAY['Street', 'Sporty', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
