VALUES ('VLR-GD-030', 'Sandal quai ngang đế bệt buckle', 'sandal-quai-ngang-de-bet-buckle', 'Sandal quai ngang màu đen được thiết kế đế bệt và khóa kim loại, tạo cảm giác thoải mái khi di chuyển. Chất liệu giả da phối đế mềm giúp sản phẩm phù hợp cho các chuyến đi ngắn hoặc dạo phố. Kiểu dáng tối giản giúp dễ phối với quần linen, váy dài hoặc set resort.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 360000, 599000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_sandal-quai-ngang-de-bet-buckle_jet-black_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
