VALUES ('VLR-GD-033', 'Giày Boots Biker Đế Platform Đen Nhiều Khóa', 'giay-boots-biker-de-platform-den-nhieu-khoa', 'Boots biker cổ cao (mid-calf) chất da đen, đế platform dày chunky với nhiều dây đai khóa kim loại quanh thân giày tạo điểm nhấn punk mạnh mẽ. Mũi giày tròn, đế răng cưa chống trượt. Thiết kế mang hơi hướng grunge, K-pop stage fashion, cực kỳ phù hợp để nâng tầm các set đồ streetwear hay tiệc tối.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 750000, 1050000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-boots-biker-de-platform-den-nhieu-khoa_black_01.png']::VARCHAR(255)[], ARRAY['Street', 'Sporty', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], NULL, false, false, '(để trống)', 'on_sale'::product_status)
