VALUES ('VLR-GD-034', 'Sandal cao gót quai ngang olive', 'sandal-cao-got-quai-ngang-olive', 'Sandal cao gót quai ngang màu olive được thiết kế mảnh, tạo cảm giác thanh thoát và nữ tính. Chất liệu giả da mềm phối gót cao vừa phải giúp tổng thể outfit trông chỉn chu hơn. Mẫu giày phù hợp với chân váy mini, đầm lụa hoặc các set đi biển theo phong cách sang nhẹ.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 380000, 629000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_sandal-cao-got-quai-ngang-olive_olive-green_1.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
