VALUES ('VLR-GD-035', 'Giày búp bê ánh vàng đính nơ', 'giay-bup-be-anh-vang-dinh-no', 'Giày búp bê ánh vàng được thiết kế mũi tròn, quai đính chi tiết kim loại và nơ nhỏ phía trước. Chất liệu giả da ánh nhẹ giúp đôi giày trông nổi bật nhưng vẫn mềm mại, nữ tính. Sản phẩm phù hợp với quần trắng, váy mini hoặc các set resort hẹn hò mùa hè.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 450000, 729000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-bup-be-anh-vang-dinh-no_champagne-gold_1.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
