VALUES ('VLR-GD-036', 'Giày Sneaker Platform Đế Bánh Mì Xám Đen', 'giay-sneaker-platform-de-banh-mi-xam-den', 'Giày sneaker platform với upper xám nhạt kết hợp da tổng hợp/suede pha mesh, đế bánh mì dày màu đen chắc chắn. Form tròn, đệm êm ái, tăng chiều cao nhưng vẫn thoải mái khi di chuyển. Thiết kế cân bằng độ rộng của quần ống lớn, mang lại vẻ ngoài trẻ trung, năng động, rất phù hợp với phong cách streetwear Hàn Quốc và Y2K.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 700000, 960000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_giay-sneaker-platform-de-banh-mi-xam-den_light-grey_01.png']::VARCHAR(255)[], ARRAY['Street', 'Sporty', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel', 'Sport']::VARCHAR(50)[], NULL, false, false, NULL, 'on_sale'::product_status)
