VALUES ('VLR-GD-037', 'Sandal bệt quai H nâu caramel', 'sandal-bet-quai-h-nau-caramel', 'Sandal bệt quai H màu nâu caramel có thiết kế đơn giản, dễ mang và phù hợp với các chuyến đi cần di chuyển nhiều. Chất liệu giả da mềm phối đường chỉ nổi tạo cảm giác casual nhưng vẫn chỉn chu. Mẫu dép dễ phối cùng quần linen, váy dài hoặc các set boho mùa hè.', (SELECT category_id FROM category WHERE slug = 'giay-dep' LIMIT 1), 340000, 559000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/giay-dep/giay-dep_sandal-bet-quai-h-nau-caramel_caramel-brown_1.png']::VARCHAR(255)[], ARRAY['Boho', 'Minimalist', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
