VALUES ('VLR-PK-001', 'Kính Mắt Bordeaux Oval', 'kinh-mat-bordeaux-oval', 'Kính mắt thời trang dáng oval thanh mảnh với gọng acetate bóng cao cấp. Tông màu Bordeaux sang trọng mang hơi hướng Y2K hiện đại, dễ phối cùng nhiều phong cách từ công sở đến dạo phố. Thiết kế nhẹ, ôm gọn khuôn mặt và tạo điểm nhấn tinh tế cho tổng thể trang phục.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 200000, 249000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kinh-mat-bordeaux-oval_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Smart Casual', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
