VALUES ('VLR-PK-002', 'Túi Đeo Vai Hobo Patent', 'tui-deo-vai-hobo-patent', 'Túi đeo vai dáng hobo được chế tác từ chất liệu giả da bóng cao cấp với thiết kế mềm mại và hiện đại. Phom túi bo cong thanh lịch mang cảm hứng Y2K, phù hợp cho nhiều phong cách từ công sở đến dạo phố. Chất liệu bóng tạo điểm nhấn sang trọng và dễ phối cùng các trang phục thường ngày.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 150000, 300000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-deo-vai-hobo-patent_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-deo-vai-hobo-patent_02.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
