INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-PK-003', 'Mũ Newsboy Vải Denim Mềm Mại', 'mu-newsboy-vai-denim-mem-mai', 'Chiếc mũ newsboy được gia công từ chất liệu vải denim mềm mại, mang lại cảm giác nhẹ nhàng, thoáng mát và vô cùng thoải mái khi đội. Thiết kế phom dáng phồng nhẹ đặc trưng kết hợp cùng những đường chỉ trần nổi bật tạo nên nét cá tính và bụi bặm. Đây là món phụ kiện không thể thiếu để hoàn thiện các set đồ dạo phố năng động hay phong cách đường phố (Street style) trẻ trung.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 180000, 250000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-newsboy-vai-denim-mem-mai_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-newsboy-vai-denim-mem-mai_02.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-newsboy-vai-denim-mem-mai_03.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-newsboy-vai-denim-mem-mai_04.png', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-newsboy-vai-denim-mem-mai_05.png']::VARCHAR(255)[], ARRAY['Street', 'Casual', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
