VALUES ('VLR-PK-005', 'Bờm Tóc Da Bóng Đính Nơ Nữ Tính', 'bom-toc-da-bong-dinh-no-nu-tinh', 'Chiếc bờm tóc được chế tác từ chất liệu da láng bóng cao cấp, mang lại vẻ ngoài sang trọng và bắt mắt. Thiết kế đính nơ kép tỉ mỉ tạo điểm nhấn vô cùng nữ tính, ngọt ngào cho mái tóc của bạn. Đây là món phụ kiện hoàn hảo để hoàn thiện phong cách tiểu thư thanh lịch trong các buổi tiệc hay những ngày dạo phố.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 80000, 100000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-da-bong-dinh-no-nu-tinh_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-da-bong-dinh-no-nu-tinh_02.png']::VARCHAR(255)[], ARRAY['Romantic', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Casual', 'School']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
