VALUES ('VLR-PK-006', 'Thắt Lưng Boho Trái Tim Chuỗi Bạc', 'that-lung-boho-trai-tim-chuoi-bac', 'Chiếc thắt lưng được chế tác từ chất liệu da PU mềm mại kết hợp cùng hợp kim bạc sáng bóng không gỉ. Thiết kế vô cùng nổi bật với các mặt khóa trái tim chạm khắc hoa văn cổ điển, đi kèm chuỗi xích layer thả lơi đầy phá cách. Đây là món phụ kiện "chân ái" giúp định hình vòng eo và nâng tầm phong cách Boho hoặc Street style khi phối cùng váy suông hay quần jeans.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 150000, 220000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_that-lung-boho-trai-tim-chuoi-bac_01.jpg']::VARCHAR(255)[], ARRAY['Boho', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
