VALUES ('VLR-PK-007', 'Dây Chuyền Layer Mặt Trái Tim Cổ Điển', 'day-chuyen-layer-mat-trai-tim-co-dien', 'Dây chuyền được thiết kế nhiều lớp (layer) độc đáo, kết hợp giữa chuỗi hạt tinh tế và dây xích kim loại cá tính. Điểm nhấn nổi bật là mặt dây chuyền hình trái tim chạm khắc hoa văn tinh xảo mang đậm hơi hướng nghệ thuật hoài cổ. Đây là món phụ kiện hoàn hảo để tạo điểm nhấn phá cách cho những bộ trang phục dạo phố hay những buổi tiệc tùng sôi động.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 120000, 180000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_day-chuyen-layer-mat-trai-tim-co-dien_01.jpg']::VARCHAR(255)[], ARRAY['Boho', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
