VALUES ('VLR-PK-008', 'Kính Râm Gọng Oval Bản Dày', 'kinh-ram-gong-oval-ban-day', 'Kính râm được chế tác từ chất liệu nhựa acetate cao cấp, mang lại độ bền vượt trội và cảm giác nhẹ nhàng, thoải mái khi đeo. Thiết kế gọng oval bản dày kết hợp cùng tròng kính tối màu tạo nên vẻ ngoài đậm chất retro bí ẩn và cực kỳ sành điệu. Đây là mảnh ghép hoàn hảo để tôn lên nét cá tính cho những bộ trang phục dạo phố hay du lịch của bạn.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 120000, 190000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kinh-ram-gong-oval-ban-day_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Street', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Travel', 'Sport']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
