VALUES ('VLR-PK-010', 'Túi Xách Da Bóng Phom Dài Kẹp Nách', 'tui-xach-da-bong-phom-dai-kep-nach', 'Chiếc túi xách được hoàn thiện từ chất liệu da láng bóng cao cấp mang lại khả năng chống thấm nhẹ và vẻ ngoài bắt mắt. Thiết kế phom dáng hình thang thuôn dài độc đáo kết hợp cùng quai đeo vai thanh mảnh tạo nên nét cuốn hút điệu đà. Đây là món phụ kiện ngọt ngào lý tưởng cho những buổi hẹn hò lãng mạn, tiệc nhẹ hay những buổi dạo phố cuối tuần.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 450000, 600000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-xach-da-bong-phom-dai-kep-nach_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Party', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
