VALUES ('VLR-PK-011', 'Túi Xách Da Nhăn Khóa Cài Cổ Điển', 'tui-xach-da-nhan-khoa-cai-co-dien', 'Chiếc túi kẹp nách được gia công từ chất liệu da PU xử lý vân nhăn vintage, mang lại độ bền và vẻ đẹp vượt thời gian. Thiết kế phom túi dáng thuyền ôm sát kết hợp cùng điểm nhấn khóa cài kim loại to bản và chi tiết xếp nếp tạo nên vẻ ngoài đậm chất retro cá tính. Đây là "bảo bối" hoàn hảo để nâng tầm phong cách dạo phố hay những bộ trang phục mang hơi hướng Y2K sành điệu.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 280000, 450000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-xach-da-nhan-khoa-cai-co-dien_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-xach-da-nhan-khoa-cai-co-dien_02.jpg']::VARCHAR(255)[], ARRAY['Street', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
