VALUES ('VLR-PK-012', 'Mũ Thủy Thủ Dạ Phối Dây Thừng', 'mu-thuy-thu-da-phoi-day-thung', 'Chiếc mũ thủy thủ được chế tác từ chất liệu dạ len dày dặn, giúp giữ phom dáng vô cùng cứng cáp và mang lại cảm giác ấm áp. Điểm nhấn nổi bật nằm ở chi tiết đai dây thừng bện xoắn kết hợp cùng cúc kim loại chạm khắc mang đậm âm hưởng hải quân cổ điển. Đây là món phụ kiện hoàn hảo giúp bạn hoàn thiện phong cách dạo phố mùa lạnh với vẻ ngoài vừa thanh lịch vừa cá tính.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 160000, 250000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-thuy-thu-da-phoi-day-thung_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-thuy-thu-da-phoi-day-thung_02.jpg']::VARCHAR(255)[], ARRAY['Classic', 'Street']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
