VALUES ('VLR-PK-013', 'Mũ Cói Vành Rộng Thắt Nơ Lãng Mạn', 'mu-coi-vanh-rong-that-no-lang-man', 'Chiếc mũ được đan lát tỉ mỉ từ chất liệu sợi cói mềm nhẹ, mang lại sự thoáng mát tối đa và khả năng che nắng hiệu quả. Thiết kế vành rộng gợn sóng điệu đà kết hợp cùng chi tiết ruy băng thắt nơ to bản tạo điểm nhấn vô cùng nữ tính và bay bổng. Đây là người bạn đồng hành hoàn hảo để hoàn thiện các set đồ dạo biển hay phong cách du mục lãng mạn trong những chuyến đi.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 120000, 185000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-coi-vanh-rong-that-no-lang-man_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_mu-coi-vanh-rong-that-no-lang-man_02.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Boho', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
