VALUES ('VLR-PK-014', 'Khăn Choàng Dạ Trơn Tua Rua', 'khan-choang-da-tron-tua-rua', 'Chiếc khăn choàng được dệt từ chất liệu dạ len mềm mịn, mang lại khả năng giữ ấm tuyệt vời và cảm giác êm ái trên da. Thiết kế trơn màu tối giản kết hợp cùng chi tiết tua rua ở hai đầu khăn tạo nên vẻ ngoài thanh lịch và tinh tế. Đây là món phụ kiện không thể thiếu để ủ ấm cơ thể và thăng hạng phong cách cho những set đồ mùa đông của bạn.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 150000, 220000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_khan-choang-da-tron-tua-rua_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_khan-choang-da-tron-tua-rua_02.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_khan-choang-da-tron-tua-rua_03.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
