VALUES ('VLR-PK-016', 'Bờm Tóc Bản To Thêu Hoa Vintage', 'bom-toc-ban-to-theu-hoa-vintage', 'Chiếc bờm tóc được hoàn thiện từ chất liệu vải lưới mỏng nhẹ kết hợp cùng các họa tiết hoa thêu nổi vô cùng tinh xảo và sắc nét. Thiết kế bản to ôm sát đầu không chỉ giúp giữ nếp tóc gọn gàng mà còn mang lại vẻ ngoài đài các, phảng phất âm hưởng đồng quê lãng mạn. Đây là món phụ kiện hoàn hảo để tô điểm thêm nét nữ tính và ngọt ngào cho phong cách thường ngày của bạn.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 65000, 100000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-theu-hoa-vintage_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-theu-hoa-vintage_02.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-theu-hoa-vintage_03.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Vintage', 'Boho']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'School', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
