VALUES ('VLR-PK-017', 'Bờm Tóc Bản To Bọc Vải Cổ Điển', 'bom-toc-ban-to-boc-vai-co-dien', 'Chiếc bờm tóc bản to được bọc cẩn thận bằng chất liệu nhung và lụa cao cấp, mang lại cảm giác vô cùng êm ái, không gây đau nhức khi cài lâu. Thiết kế trơn màu tối giản với phom dáng phồng nhẹ giúp tạo độ bồng bềnh cho mái tóc và tôn lên các đường nét trên khuôn mặt. Đây là món phụ kiện cơ bản nhưng vô cùng "có võ", giúp các quý cô hoàn thiện phong cách thanh lịch, đài các trong mọi hoàn cảnh.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 40000, 75000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-boc-vai-co-dien_01.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-boc-vai-co-dien_02.jpg', 'https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_bom-toc-ban-to-boc-vai-co-dien_03.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Elegant']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'School', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
