VALUES ('VLR-PK-018', 'Thắt Lưng Da Đan Khóa Chữ D', 'that-lung-da-dan-khoa-chu-d', 'Chiếc thắt lưng được gia công tỉ mỉ từ chất liệu da PU mềm mại với kỹ thuật đan chéo tinh xảo. Thiết kế bản nhỏ thanh lịch kết hợp cùng mặt khóa kim loại mạ vàng sáng bóng tạo điểm nhấn mang đậm chất cổ điển. Đây là món phụ kiện linh hoạt giúp định hình vòng eo và tôn lên vẻ đẹp của những chiếc váy suông hay quần jeans năng động.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 120000, 180000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_that-lung-da-dan-khoa-chu-d_01.jpg']::VARCHAR(255)[], ARRAY['Classic', 'Minimalist', 'Boho']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
