VALUES ('VLR-PK-019', 'Thắt Lưng Kim Loại Họa Tiết Boho', 'that-lung-kim-loai-hoa-tiet-boho', 'Chiếc thắt lưng được hoàn thiện từ chất liệu hợp kim cao cấp chống gỉ sét, mang lại độ sáng bóng tự nhiên và độ bền bỉ vượt thời gian. Thiết kế chuỗi xích nối liền các mặt kim loại chạm khắc họa tiết tinh xảo, đi kèm dải xích thả lơi giúp tôn lên vòng eo thon gọn. Đây là điểm nhấn hoàn hảo mang đậm chất du mục phóng khoáng, cực kỳ ăn ý khi phối cùng váy maxi thướt tha hay quần jeans bụi bặm.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 90000, 145000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_that-lung-kim-loai-hoa-tiet-boho_01.jpg']::VARCHAR(255)[], ARRAY['Boho', 'Street']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
