VALUES ('VLR-PK-037', 'Choker Ngọc Trai Thiên Nhiên Phối Charm Trái Tim Đính Đá Pearl White', 'choker-ngoc-trai-thien-nhien-phoi-charm-trai-tim-dinh-da-pearl-white', 'Chuỗi vòng cổ choker được kết từ những viên ngọc trai thiên nhiên chọn lọc kỹ lưỡng, mang sắc trắng ngà vương giả. Điểm xuyết ở trung tâm là một chiếc charm trái tim đính kim cương nhân tạo, mang lại diện mạo ngọt ngào, kiêu sang chuẩn tiểu thư.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 3500000, 3500000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_choker-ngoc-trai-thien-nhien-phoi-charm-trai-tim-dinh-da_pearl-white_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Party']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
