VALUES ('VLR-PK-038', 'Kẹp Tóc Kim Loại Đính Đá Kim Cương Biểu Tượng Diamond Silver', 'kep-toc-kim-loai-dinh-da-kim-cuong-bieu-tuong-diamond-silver', 'Chiếc kẹp tóc kim loại cao cấp được tạo hình biểu tượng nghệ thuật đính đá kim cương toàn bản lấp lánh. Một món phụ kiện tóc tinh tế, giúp cố định những lọn tóc uốn lượn sang trọng và tôn lên thần thái kiêu kỳ của quý cô.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 1800000, 1800000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kep-toc-kim-loai-dinh-da-kim-cuong-bieu-tuong_diamond-silver_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Party']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
