VALUES ('VLR-PK-039', 'Khuyên Tai Nụ Đính Đá Toàn Bản Biểu Tượng Double G Diamond Silver', 'khuyen-tai-nu-dinh-da-toan-ban-bieu-tuong-double-g-diamond-silver', 'Đôi khuyên tai dáng nụ mang biểu tượng Double G huyền thoại, được phủ kín bằng những viên đá kim cương nhân tạo lấp lánh bậc nhất. Thiết kế thời thượng, đẳng cấp, là tuyên ngôn phong cách mạnh mẽ cho những đêm tiệc xa hoa.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 2400000, 2400000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_khuyen-tai-nu-dinh-da-toan-ban-bieu-tuong-double-g_diamond-silver_01.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Party']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
