INSERT INTO product (sku, name, slug, description, category_id, base_price, sale_price, images, style_tags, color_tone, occasions, suitable_body_shapes, is_combo, is_featured, collection, status)
VALUES ('VLR-PK-040', 'Túi Đeo Chéo Mini Hình Chữ Nhật Trắng Ngà Đính Đinh', 'tui-deo-cheo-mini-hinh-chu-nhat-trang-nga-dinh-dinh', 'Túi đeo chéo mini với form dáng chữ nhật mềm mại, được làm từ chất liệu da PU cao cấp màu trắng ngà. Điểm nhấn là dây đeo bản nhỏ được trang trí bằng các đinh tán kim loại sáng bóng, mang lại vẻ ngoài cá tính và sành điệu. Kích thước vừa đủ để đựng điện thoại, son môi và các vật dụng nhỏ, là phụ kiện hoàn hảo cho phong cách Y2K hay streetwear.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 220000, 350000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-deo-cheo-mini-hinh-chu-nhat-trang-nga-dinh-dinh_ivory_01.png']::VARCHAR(255)[], ARRAY['Street', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
