VALUES ('VLR-PK-042', 'Túi Cầm Tay Canvas Ivory Tối Giản', 'tui-cam-tay-canvas-ivory-toi-gian', 'Mẫu túi cầm tay dáng chữ nhật nhỏ gọn với phom cứng cáp vừa đủ, phù hợp cho những set đồ thanh lịch và tối giản. Tông Ivory sáng giúp phụ kiện dễ kết hợp với bảng màu trung tính như Cocoa, Pearl hay Sage. Đây là món phụ kiện phù hợp cho tiệc nhẹ, hẹn hò hoặc đi làm theo phong cách chỉn chu hiện đại.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 450000, 620000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-cam-tay-canvas-ivory-toi-gian_01.jpg']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
