VALUES ('VLR-PK-043', 'Túi Cầm Tay Vòng Kim Loại Pearl', 'tui-cam-tay-vong-kim-loai-pearl', 'Thiết kế túi cầm tay dáng cong mềm với quai vòng kim loại tạo điểm nhấn sang trọng nhưng vẫn tinh tế. Gam Pearl/Ivory nhã nhặn giúp món phụ kiện này dễ đi cùng các set đồ dự tiệc, chụp ảnh hoặc hẹn tối. Kiểu dáng tối giản nhưng vẫn đủ nổi bật để hoàn thiện vẻ ngoài nữ tính, thanh lịch.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 520000, 720000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-cam-tay-vong-kim-loai-pearl_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Minimalist', 'Classic']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, true, NULL, 'on_sale'::product_status)
