VALUES ('VLR-PK-044', 'Hoa Tai Vòng Xoắn Ánh Vàng', 'hoa-tai-vong-xoan-anh-vang', 'Đôi hoa tai vòng xoắn với bề mặt ánh vàng giúp tổng thể trang phục trông sang và hoàn thiện hơn mà không quá cầu kỳ. Thiết kế phù hợp với tinh thần thanh lịch hiện đại, dễ phối cùng áo kiểu mềm, quần suông hoặc váy midi. Đây là điểm nhấn nhỏ nhưng hiệu quả cho những dịp hẹn hò, tiệc nhẹ hay chụp ảnh.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 220000, 320000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_hoa-tai-vong-xoan-anh-vang_01.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Classic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party', 'Office']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
