VALUES ('VLR-PK-045', 'Túi Top Handle Croc Sage Nhẹ Nhàng', 'tui-top-handle-croc-sage-nhe-nhang', 'Mẫu túi top-handle mini với bề mặt giả vân croc tạo cảm giác gọn gàng và sang hơn cho tổng thể. Tông Sage dịu mắt giúp phụ kiện vừa có điểm nhấn vừa vẫn giữ được sự mềm mại đặc trưng của Soft Ceremony. Phù hợp để phối cùng các set đồ đi cà phê, du lịch hoặc hẹn hò ban ngày.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 560000, 780000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-top-handle-croc-sage-nhe-nhang_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Classic', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Travel', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
