VALUES ('VLR-PK-046', 'Hoa Tai Đá Giọt Nước Ánh Vàng', 'hoa-tai-da-giot-nuoc-anh-vang', 'Thiết kế hoa tai mảnh với chi tiết đá giọt nước mang đến cảm giác nữ tính và thanh thoát. Phụ kiện phù hợp để tăng độ chỉn chu cho các set đồ tối giản mà vẫn giữ được vẻ nhẹ nhàng, tinh tế. Đặc biệt phù hợp với các buổi tiệc tối, hẹn hò hoặc dịp cần vẻ ngoài sang hơn thường ngày.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 240000, 350000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_hoa-tai-da-giot-nuoc-anh-vang_01.jpg']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
