VALUES ('VLR-PK-047', 'Đồng Hồ Mặt Vuông Dây Kim Loại Vàng', 'dong-ho-mat-vuong-day-kim-loai-vang', 'Mẫu đồng hồ mặt vuông nhỏ gọn với dây kim loại ánh vàng mang tinh thần cổ điển, thanh lịch và trưởng thành. Thiết kế phù hợp để hoàn thiện những set đồ dự tiệc nhẹ hoặc công sở tinh tế mà không cần quá nhiều phụ kiện đi kèm. Tông vàng ấm cũng giúp tổng thể trông sang hơn khi phối cùng Cocoa, Ivory hoặc Pearl.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 680000, 920000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_dong-ho-mat-vuong-day-kim-loai-vang_01.jpg']::VARCHAR(255)[], ARRAY['Classic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Office', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Rectangle', 'Apple', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
