VALUES ('VLR-PK-049', 'Túi Baguette Shoulder Mini Màu Kem Nhạt', 'tui-baguette-shoulder-mini-mau-kem-nhat', 'Túi baguette shoulder mini dáng ngang, thiết kế tối giản với quai ngắn đeo sát vai. Chất liệu da PU mềm mại màu kem nhạt, không logo nổi bật, giữ vẻ thanh lịch và tinh tế. Phom dáng nhỏ gọn, đựng vừa các vật dụng cần thiết. Là món phụ kiện Y2K không thể thiếu, dễ dàng phối với nhiều phong cách từ công sở đến dạo phố.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 300000, 450000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-baguette-shoulder-mini-mau-kem-nhat_cream_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Classic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Office', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
