VALUES ('VLR-PK-051', 'Túi tote canvas phối viền beige', 'tui-tote-canvas-phoi-vien-beige', 'Túi tote canvas phối viền beige có phom rộng, phù hợp mang theo khi đi chơi, du lịch hoặc dạo phố. Chất liệu canvas tạo cảm giác nhẹ nhàng, tự nhiên và dễ phối với các outfit mùa hè. Thiết kế tối giản giúp tổng thể set đồ thêm cân bằng và tiện dụng.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 220000, 359000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-tote-canvas-phoi-vien-beige_1.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
