VALUES ('VLR-PK-052', 'Kính râm oval vintage đen', 'kinh-ram-oval-vintage-den', 'Kính râm dáng oval màu đen mang cảm giác vintage và hiện đại, phù hợp làm điểm nhấn cho outfit mùa hè. Thiết kế nhỏ gọn, tròng nâu nhẹ giúp tổng thể trang phục trông cá tính hơn. Phụ kiện này phù hợp với các set đi biển, dạo phố hoặc resort casual.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 180000, 299000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kinh-ram-oval-vintage-den_1.png']::VARCHAR(255)[], ARRAY['Street', 'Smart Casual', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
