VALUES ('VLR-PK-053', 'Túi Đeo Vai Mini Hình Chữ Nhật Đen Khóa Bạc', 'tui-deo-vai-mini-hinh-chu-nhat-den-khoa-bac', 'Túi đeo vai mini dáng chữ nhật đứng nhỏ gọn, màu đen toàn bộ với chi tiết quai đeo đính khoen kim loại bạc sáng. Chất liệu da PU cứng cáp giữ form tốt, kích thước vừa đủ đựng điện thoại và ví nhỏ. Phong cách Y2K minimal punk, dễ dàng phối cùng trang phục streetwear hay tiệc tối.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 250000, 380000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-deo-vai-mini-hinh-chu-nhat-den-khoa-bac_black_01.png']::VARCHAR(255)[], ARRAY['Minimalist', 'Street', 'Classic']::VARCHAR(50)[], 'Cool'::skin_tone, ARRAY['Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
