VALUES ('VLR-PK-055', 'Vòng tay cỏ bốn lá olive gold', 'vong-tay-co-bon-la-olive-gold', 'Vòng tay cỏ bốn lá phối nền olive và dây gold tạo điểm nhấn nữ tính, tinh tế cho cổ tay. Thiết kế nhỏ gọn, màu sắc hài hòa với áo và kính trong set đồ. Phụ kiện phù hợp để hoàn thiện các outfit resort, casual hoặc hẹn hò mùa hè.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 160000, 259000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_vong-tay-co-bon-la-olive-gold_1.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
