VALUES ('VLR-PK-056', 'Túi cầm tay ivory quai tròn vàng', 'tui-cam-tay-ivory-quai-tron-vang', 'Túi cầm tay màu ivory có phom bán nguyệt mềm mại và quai tròn ánh vàng tạo cảm giác sang trọng. Chất liệu bề mặt mịn, thiết kế nhỏ gọn nhưng đủ nổi bật để làm điểm nhấn cho set đồ. Sản phẩm phù hợp với phong cách resort chic, tiệc nhẹ hoặc dạo phố mùa hè.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 320000, 499000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-cam-tay-ivory-quai-tron-vang_1.jpg']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic', 'Smart Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
