VALUES ('VLR-PK-057', 'Túi mini hồng pastel', 'tui-mini-hong-pastel', 'Túi mini màu hồng pastel có phom cong mềm mại, tạo điểm nhấn ngọt ngào cho outfit trắng. Chất liệu bề mặt mịn phối chi tiết ánh vàng giúp tổng thể trông nữ tính và sang hơn. Sản phẩm phù hợp cho dạo phố, hẹn hò hoặc du lịch nhẹ.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 330000, 529000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-mini-hong-pastel_1.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual', 'Party']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
