VALUES ('VLR-PK-059', 'Set trang sức gold trái tim và ngôi sao', 'set-trang-suc-gold-trai-tim-va-ngoi-sao', 'Set trang sức gold gồm hoa tai và vòng tay với chi tiết trái tim, ngôi sao nhỏ tạo cảm giác nữ tính và nổi bật vừa phải. Thiết kế ánh vàng giúp outfit trắng trở nên mềm mại và có điểm nhấn hơn. Phụ kiện phù hợp cho các set hẹn hò, đi chơi hoặc tiệc nhẹ ban ngày.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 240000, 399000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_set-trang-suc-gold-trai-tim-va-ngoi-sao_1.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
