VALUES ('VLR-PK-060', 'Túi Messenger Đeo Chéo Streetwear Xám Đen', 'tui-messenger-deo-cheo-streetwear-xam-den', 'Túi messenger đeo chéo phong cách utilitarian với thân túi màu xám, viền và dây đeo màu đen tương phản. Chất liệu nylon kỹ thuật nhẹ, bền, form mềm bo tròn. Thiết kế tối giản nhưng vẫn toát lên vẻ năng động, streetwear. Là món phụ kiện lý tưởng để tạo lớp layer thị giác cho outfit, tăng tính casual và hiện đại.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 260000, 390000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-messenger-deo-cheo-streetwear-xam-den_light-grey_01.png']::VARCHAR(255)[], ARRAY['Street', 'Casual']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
