VALUES ('VLR-PK-061', 'Kính Mát Gọng Oval Trắng', 'kinh-mat-gong-oval-trang', 'Kính mát gọng oval màu trắng bóng, thiết kế retro Y2K. Sản phẩm có thể dùng làm phụ kiện tóc bằng cách đặt trên đỉnh đầu, tạo điểm nhấn nổi bật trên nền tóc đen. Gọng nhẹ, bền, dễ phối với nhiều phong cách từ casual đến streetwear.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 180000, 280000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kinh-mat-gong-oval-trang_white_01.png']::VARCHAR(255)[], ARRAY['Classic', 'Street', 'Minimalist']::VARCHAR(50)[], 'Neutral'::skin_tone, ARRAY['Casual', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, NULL, 'on_sale'::product_status)
