VALUES ('VLR-PK-062', 'Kính râm oval gọng vàng tròng olive', 'kinh-ram-oval-gong-vang-trong-olive', 'Kính râm dáng oval gọng vàng phối tròng olive tạo điểm nhấn hiện đại và sang nhẹ cho outfit mùa hè. Thiết kế nhỏ gọn, thanh mảnh giúp cân bằng tổng thể boho mềm mại của set đồ. Phụ kiện phù hợp cho du lịch, dạo phố hoặc resort casual.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 180000, 299000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_kinh-ram-oval-gong-vang-trong-olive_1.png']::VARCHAR(255)[], ARRAY['Elegant', 'Smart Casual', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
