VALUES ('VLR-PK-063', 'Túi hobo nâu chocolate', 'tui-hobo-nau-chocolate', 'Túi hobo màu nâu chocolate có phom mềm, quai đeo vai tiện dụng và bề mặt giả da mịn. Gam nâu ấm giúp outfit màu kem và hồng pastel trở nên hài hòa, trưởng thành hơn. Sản phẩm phù hợp cho dạo phố, cà phê cuối tuần hoặc các set đi chơi nhẹ nhàng.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 280000, 459000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-hobo-nau-chocolate_1.png']::VARCHAR(255)[], ARRAY['Boho', 'Smart Casual', 'Minimalist']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Travel', 'Casual']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
