VALUES ('VLR-PK-064', 'Túi hobo mini hồng pastel', 'tui-hobo-mini-hong-pastel', 'Túi hobo mini màu hồng pastel có phom cong mềm mại, tạo điểm nhấn ngọt ngào cho outfit đen và champagne. Chất liệu bề mặt mịn phối chi tiết ánh vàng giúp tổng thể trông nữ tính và sang hơn. Sản phẩm phù hợp cho hẹn hò, tiệc nhẹ hoặc dạo phố mùa hè.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 330000, 529000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_tui-hobo-mini-hong-pastel_1.png']::VARCHAR(255)[], ARRAY['Romantic', 'Elegant', 'Smart Casual']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
