VALUES ('VLR-PK-066', 'Set trang sức gold statement', 'set-trang-suc-gold-statement', 'Set trang sức gold gồm hoa tai, đồng hồ, vòng tay và nhẫn tạo điểm nhấn nổi bật cho outfit tiệc nhẹ. Thiết kế ánh vàng giúp tổng thể trang phục trở nên sang trọng và có chiều sâu hơn. Phụ kiện phù hợp với phong cách elegant, romantic và resort glam.', (SELECT category_id FROM category WHERE slug = 'phu-kien' LIMIT 1), 280000, 459000, ARRAY['https://raw.githubusercontent.com/khai0335814880-create/Velura-Images/refs/heads/main/categories/phu-kien/phu-kien_set-trang-suc-gold-statement_1.png']::VARCHAR(255)[], ARRAY['Elegant', 'Romantic']::VARCHAR(50)[], 'Warm'::skin_tone, ARRAY['Casual', 'Party', 'Travel']::VARCHAR(50)[], ARRAY['Hourglass', 'Pear', 'Apple', 'Rectangle', 'Inverted Triangle']::body_shape[], false, false, 'Weekend Escape', 'on_sale'::product_status)
